export enum DocumentStatus {
  PENDING = 'PENDING',
  UPLOADED = 'UPLOADED',
  REJECTED = 'REJECTED'
}

export enum DocumentType {
  ID = 'Identidade (RG/CNH)',
  RESIDENCE = 'Comprovante de Residência',
  INCOME = 'Comprovante de Renda',
  CONTRACT = 'Contrato de Consórcio',
  UNKNOWN = 'Desconhecido'
}

export interface ClientDocument {
  id: string;
  type: DocumentType;
  status: DocumentStatus;
  fileName?: string;
  uploadDate?: string;
  confidence?: number;
}

export interface Client {
  id: string;
  name: string;
  cpf: string;
  consortiumType: string;
  group: string;
  quota: string;
  progress: number;
  documents: ClientDocument[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const classifyDocument = async (base64Image: string): Promise<{ type: DocumentType, confidence: number }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            {
              inlineData: {
                mimeType: "image/jpeg",
                data: base64Image
              }
            },
            {
              text: "Analise esta imagem de documento e identifique se é um RG/CNH, Comprovante de Residência, Comprovante de Renda ou Contrato de Consórcio. Retorne o resultado em JSON."
            }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classification: {
              type: Type.STRING,
              description: "O tipo do documento: 'ID', 'RESIDENCE', 'INCOME', 'CONTRACT' ou 'UNKNOWN'"
            },
            confidence: {
              type: Type.NUMBER,
              description: "Nível de confiança de 0 a 1"
            }
          },
          required: ["classification", "confidence"]
        }
      }
    });

    const result = JSON.parse(response.text || "{}");

    const typeMap: Record<string, DocumentType> = {
      'ID': DocumentType.ID,
      'RESIDENCE': DocumentType.RESIDENCE,
      'INCOME': DocumentType.INCOME,
      'CONTRACT': DocumentType.CONTRACT,
      'UNKNOWN': DocumentType.UNKNOWN
    };

    return {
      type: typeMap[result.classification] || DocumentType.UNKNOWN,
      confidence: result.confidence || 0
    };
  } catch (error) {
    console.error("Erro ao classificar documento:", error);
    return { type: DocumentType.UNKNOWN, confidence: 0 };
  }
};

