import React, { useState } from 'react';
import { Client, DocumentStatus, DocumentType } from '../types';
import { classifyDocument } from '../services/geminiService';

interface ClientDetailsProps {
  client: Client;
  onUpdateDocument: (docId: string, updates: any) => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, onUpdateDocument }) => {
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, targetDocId: string) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(targetDocId);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];

      // Use Gemini to check if it's the right document
      const result = await classifyDocument(base64Data);
      const targetDoc = client.documents.find(d => d.id === targetDocId);

      if (targetDoc) {
        const isMatch = result.type === targetDoc.type;

        onUpdateDocument(targetDocId, {
          status: DocumentStatus.UPLOADED,
          fileName: file.name,
          uploadDate: new Date().toISOString().split('T')[0],
          confidence: result.confidence
        });

        if (!isMatch && result.type !== DocumentType.UNKNOWN) {
          alert(`Aviso: O documento enviado parece ser "${result.type}", mas você o enviou no campo de "${targetDoc.type}". Por favor, verifique.`);
        }
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn">
      {/* Profile Header */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-400 text-2xl border border-slate-200">
            <i className="fa-solid fa-user"></i>
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{client.name}</h2>
            <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-sm text-slate-500">
              <span className="flex items-center gap-1.5"><i className="fa-solid fa-id-card text-xs"></i> {client.cpf}</span>
              <span className="flex items-center gap-1.5"><i className="fa-solid fa-folder-tree text-xs"></i> Grupo: {client.group} / Cota: {client.quota}</span>
              <span className="flex items-center gap-1.5 font-medium text-indigo-600">{client.consortiumType}</span>
            </div>
          </div>
        </div>
        <div className="w-full md:w-auto flex flex-col items-end gap-1">
          <span className="text-sm font-semibold text-slate-700">Progresso Documental</span>
          <div className="w-full md:w-48 h-3 bg-slate-100 rounded-full overflow-hidden border border-slate-200">
            <div 
              className={`h-full transition-all duration-1000 ease-out ${
                client.progress === 100 ? 'bg-emerald-500' : 'bg-indigo-600'
              }`} 
              style={{ width: `${client.progress}%` }}
            ></div>
          </div>
          <span className="text-xs text-slate-400 font-medium">{client.progress}% Concluído</span>
        </div>
      </div>

      {/* Document List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {client.documents.map((doc) => (
          <div 
            key={doc.id}
            className={`bg-white rounded-xl border p-5 transition-all ${
              doc.status === DocumentStatus.UPLOADED 
                ? 'border-emerald-200 bg-emerald-50/20' 
                : 'border-slate-200 hover:border-indigo-300'
            }`}
          >
            <div className="flex justify-between items-start mb-4">
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                  doc.status === DocumentStatus.UPLOADED ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'
                }`}>
                  <i className={`fa-solid ${
                    doc.type === DocumentType.ID ? 'fa-address-card' :
                    doc.type === DocumentType.RESIDENCE ? 'fa-house' :
                    doc.type === DocumentType.INCOME ? 'fa-receipt' :
                    'fa-file-signature'
                  }`}></i>
                </div>
                <div>
                  <h3 className="font-semibold text-slate-800 text-sm leading-tight">{doc.type}</h3>
                  <span className={`text-[10px] font-bold uppercase tracking-wider ${
                    doc.status === DocumentStatus.UPLOADED ? 'text-emerald-600' : 'text-slate-400'
                  }`}>
                    {doc.status === DocumentStatus.UPLOADED ? 'Recebido' : 'Pendente'}
                  </span>
                </div>
              </div>

              {doc.status === DocumentStatus.UPLOADED && (
                <div className="flex items-center gap-2">
                   <button className="p-1.5 text-slate-400 hover:text-indigo-600 transition-colors">
                     <i className="fa-solid fa-eye text-sm"></i>
                   </button>
                   <button className="p-1.5 text-slate-400 hover:text-red-500 transition-colors">
                     <i className="fa-solid fa-trash text-sm"></i>
                   </button>
                </div>
              )}
            </div>

            {doc.status === DocumentStatus.UPLOADED ? (
              <div className="space-y-2">
                <div className="flex items-center justify-between text-xs text-slate-500 bg-white/60 p-2 rounded-lg border border-emerald-100">
                  <span className="truncate max-w-[150px]"><i className="fa-solid fa-file-pdf mr-1 text-red-400"></i> {doc.fileName}</span>
                  <span className="whitespace-nowrap">{doc.uploadDate}</span>
                </div>
                {doc.confidence && (
                  <div className="flex items-center gap-2 text-[10px] text-slate-400">
                    <i className="fa-solid fa-robot text-indigo-400"></i>
                    <span>Identificado por IA (Confiança: {(doc.confidence * 100).toFixed(0)}%)</span>
                  </div>
                )}
              </div>
            ) : (
              <div>
                <label className="group relative flex items-center justify-center border-2 border-dashed border-slate-200 rounded-xl py-6 cursor-pointer hover:border-indigo-400 hover:bg-indigo-50/50 transition-all overflow-hidden">
                  {isProcessing === doc.id ? (
                    <div className="flex flex-col items-center gap-2">
                      <div className="w-6 h-6 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                      <span className="text-xs font-medium text-indigo-600">IA Identificando...</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center gap-1">
                      <i className="fa-solid fa-cloud-arrow-up text-slate-300 group-hover:text-indigo-400 transition-colors text-xl"></i>
                      <span className="text-xs font-medium text-slate-500 group-hover:text-indigo-600">Enviar Documento</span>
                    </div>
                  )}
                  <input 
                    type="file" 
                    className="hidden" 
                    accept="image/*,application/pdf"
                    onChange={(e) => handleFileUpload(e, doc.id)}
                    disabled={isProcessing === doc.id}
                  />
                </label>
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Action Bar */}
      <div className="mt-4 flex flex-col sm:flex-row items-center justify-between p-6 bg-slate-800 rounded-2xl text-white gap-4">
        <div>
          <h4 className="font-semibold">Próximo Passo</h4>
          <p className="text-sm text-slate-400">
            {client.progress === 100 
              ? "Tudo pronto! Envie para análise da administradora." 
              : `Aguardando ${client.documents.filter(d => d.status === DocumentStatus.PENDING).length} documento(s) para conclusão.`}
          </p>
        </div>
        <button 
          disabled={client.progress < 100}
          className={`px-8 py-3 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2 ${
            client.progress === 100 
              ? 'bg-indigo-600 hover:bg-indigo-700 hover:scale-105' 
              : 'bg-slate-700 text-slate-500 cursor-not-allowed'
          }`}
        >
          <i className="fa-solid fa-paper-plane"></i>
          Enviar para Análise
        </button>
      </div>
    </div>
  );
};

