import React, { useState } from 'react';
import { Client, DocumentStatus, DocumentType } from '../types';
import { classifyDocument } from '../services/geminiService';

interface ClientDetailsProps {
  client: Client;
  onUpdateDocument: (docId: string, updates: any) => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, onUpdateDocument }) => {
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, targetDocId: string) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(targetDocId);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);
      const targetDoc = client.documents.find(d => d.id === targetDocId);

      if (targetDoc) {
        const isMatch = result.type === targetDoc.type;

        onUpdateDocument(targetDocId, {
          status: DocumentStatus.UPLOADED,
          fileName: file.name,
          uploadDate: new Date().toISOString().split('T')[0],
          confidence: result.confidence
        });

        if (!isMatch && result.type !== DocumentType.UNKNOWN) {
          alert(`Aviso: O documento enviado parece ser "${result.type}", mas você o enviou no campo de "${targetDoc.type}". Por favor, verifique.`);
        }
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn">
      {/* Profile Header */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-slate-50 rounded-2xl flex items-center justify-center text-indigo-500 text-2xl border border-slate-200 shadow-inner">
            <i className="fa-solid fa-user-check"></i>
          </div>
          <div>
            <div className="flex items-center gap-3">
              <h2 className="text-2xl font-bold text-slate-800">{client.name}</h2>
              <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-full uppercase border border-indigo-100">
                {client.consortiumType}
              </span>
            </div>

            <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-sm text-slate-500">
              <span className="flex items-center gap-1.5"><i className="fa-solid fa-id-card text-xs text-slate-400"></i> {client.cpf}</span>
              <span className="flex items-center gap-1.5"><i className="fa-solid fa-tags text-xs text-slate-400"></i> Grupo: <b className="text-slate-700">{client.group}</b> / Cota: <b className="text-slate-700">{client.quota}</b></span>
            </div>

            <div className="mt-3 flex items-center gap-2">
               <div className="flex -space-x-2">
                 <img src={`https://ui-avatars.com/api/?name=${encodeURIComponent(client.analystName)}&background=6366f1&color=fff`} className="w-6 h-6 rounded-full border-2 border-white" alt="Analyst" />
               </div>
               <span className="text-xs text-slate-500">Analista Responsável: <strong className="text-slate-800">{client.analystName}</strong></span>
            </div>
          </div>
        </div>

        <div className="w-full md:w-auto flex flex-col items-end gap-1 bg-slate-50 p-4 rounded-xl border border-slate-100">
          <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Status da Documentação</span>
          <div className="w-full md:w-48 h-2.5 bg-slate-200 rounded-full overflow-hidden mt-1">
            <div 
              className={`h-full transition-all duration-1000 ease-out shadow-sm ${
                client.progress === 100 ? 'bg-emerald-500' : 'bg-indigo-600'
              }`} 
              style={{ width: `${client.progress}%` }}
            ></div>
          </div>
          <span className={`text-sm font-bold mt-1 ${client.progress === 100 ? 'text-emerald-600' : 'text-indigo-600'}`}>
            {client.progress}% Concluído
          </span>
        </div>
      </div>

      {/* Document List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {client.documents.map((doc) => (
          <div 
            key={doc.id}
            className={`bg-white rounded-xl border p-5 transition-all relative overflow-hidden group ${
              doc.status === DocumentStatus.UPLOADED 
                ? 'border-emerald-200 bg-emerald-50/10' 
                : 'border-slate-200 hover:border-indigo-300'
            }`}
          >
            {doc.status === DocumentStatus.UPLOADED && (
              <div className="absolute top-0 right-0 w-12 h-12 bg-emerald-500/10 rounded-bl-3xl flex items-start justify-end p-2">
                <i className="fa-solid fa-check text-emerald-500 text-xs"></i>
              </div>
            )}

            <div className="flex justify-between items-start mb-4">
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center transition-colors ${
                  doc.status === DocumentStatus.UPLOADED ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400 group-hover:bg-indigo-100 group-hover:text-indigo-600'
                }`}>
                  <i className={`fa-solid ${
                    doc.type === DocumentType.ID ? 'fa-address-card' :
                    doc.type === DocumentType.RESIDENCE ? 'fa-house' :
                    doc.type === DocumentType.INCOME ? 'fa-receipt' :
                    'fa-file-signature'
                  }`}></i>
                </div>
                <div>
                  <h3 className="font-semibold text-slate-800 text-sm leading-tight">{doc.type}</h3>
                  <span className={`text-[10px] font-bold uppercase tracking-wider ${
                    doc.status === DocumentStatus.UPLOADED ? 'text-emerald-600' : 'text-slate-400'
                  }`}>
                    {doc.status === DocumentStatus.UPLOADED ? 'Recebido' : 'Pendente'}
                  </span>
                </div>
              </div>

              {doc.status === DocumentStatus.UPLOADED && (
                <div className="flex items-center gap-1">
                   <button title="Visualizar" className="p-1.5 text-slate-400 hover:text-indigo-600 transition-colors">
                     <i className="fa-solid fa-eye text-sm"></i>
                   </button>
                   <button title="Excluir" className="p-1.5 text-slate-400 hover:text-red-500 transition-colors">
                     <i className="fa-solid fa-trash text-sm"></i>
                   </button>
                </div>
              )}
            </div>

            {doc.status === DocumentStatus.UPLOADED ? (
              <div className="space-y-2">
                <div className="flex items-center justify-between text-xs text-slate-500 bg-white p-2 rounded-lg border border-emerald-100 shadow-sm">
                  <span className="truncate max-w-[150px]"><i className="fa-solid fa-file-image mr-1 text-emerald-500"></i> {doc.fileName}</span>
                  <span className="whitespace-nowrap text-[10px] bg-slate-50 px-1.5 py-0.5 rounded border border-slate-100">{doc.uploadDate}</span>
                </div>
                {doc.confidence && (
                  <div className="flex items-center gap-2 text-[10px] text-slate-400 bg-indigo-50/30 p-1.5 rounded-md border border-indigo-100/30">
                    <i className="fa-solid fa-robot text-indigo-400"></i>
                    <span>IA validou este documento com <strong>{(doc.confidence * 100).toFixed(0)}%</strong> de certeza.</span>
                  </div>
                )}
              </div>
            ) : (
              <div>
                <label className="group/label relative flex items-center justify-center border-2 border-dashed border-slate-200 rounded-xl py-6 cursor-pointer hover:border-indigo-400 hover:bg-indigo-50/50 transition-all overflow-hidden bg-slate-50/30">
                  {isProcessing === doc.id ? (
                    <div className="flex flex-col items-center gap-2">
                      <div className="w-6 h-6 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                      <span className="text-xs font-medium text-indigo-600">Processando com Gemini...</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center gap-1">
                      <i className="fa-solid fa-arrow-up-from-bracket text-slate-300 group-hover/label:text-indigo-400 transition-colors text-xl"></i>
                      <span className="text-xs font-medium text-slate-500 group-hover/label:text-indigo-600 text-center px-4">
                        Clique ou arraste o arquivo aqui
                      </span>
                    </div>
                  )}
                  <input 
                    type="file" 
                    className="hidden" 
                    accept="image/*,application/pdf"
                    onChange={(e) => handleFileUpload(e, doc.id)}
                    disabled={isProcessing === doc.id}
                  />
                </label>
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Action Bar */}
      <div className="mt-4 flex flex-col sm:flex-row items-center justify-between p-6 bg-slate-900 rounded-2xl text-white gap-6 border-l-8 border-indigo-500 shadow-xl">
        <div className="flex items-center gap-4">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl shadow-inner ${
             client.progress === 100 ? 'bg-emerald-500 text-white' : 'bg-slate-800 text-slate-500'
          }`}>
            <i className={`fa-solid ${client.progress === 100 ? 'fa-circle-check' : 'fa-clock'}`}></i>
          </div>
          <div>
            <h4 className="font-bold text-lg leading-tight">Status Final da Proposta</h4>
            <p className="text-sm text-slate-400">
              {client.progress === 100 
                ? `Tudo pronto! Analista ${client.analystName} pode prosseguir.` 
                : `Aguardando o envio de mais ${client.documents.filter(d => d.status === DocumentStatus.PENDING).length} documento(s).`}
            </p>
          </div>
        </div>
        <button 
          disabled={client.progress < 100}
          className={`px-10 py-4 rounded-xl font-bold transition-all shadow-lg flex items-center gap-3 whitespace-nowrap text-base ${
            client.progress === 100 
              ? 'bg-indigo-600 hover:bg-indigo-700 hover:scale-[1.02] active:scale-95 text-white' 
              : 'bg-slate-800 text-slate-600 cursor-not-allowed border border-slate-700'
          }`}
        >
          <i className="fa-solid fa-paper-plane"></i>
          Enviar para Faturamento
        </button>
      </div>
    </div>
  );
};

