import React from 'react';
import { Client, DocumentStatus } from '../types';

interface ReportsProps {
  clients: Client[];
}

const Reports: React.FC<ReportsProps> = ({ clients }) => {
  const totalClients = clients.length;
  const completedProposals = clients.filter(c => c.progress === 100).length;
  const averageProgress = clients.reduce((acc, c) => acc + c.progress, 0) / totalClients;

  const totalDocs = clients.reduce((acc, c) => acc + c.documents.length, 0);
  const uploadedDocs = clients.reduce((acc, c) => acc + c.documents.filter(d => d.status === DocumentStatus.UPLOADED).length, 0);
  const pendingDocs = totalDocs - uploadedDocs;

  // Group by Analyst
  const analystStats = clients.reduce((acc: any, c) => {
    if (!acc[c.analystName]) acc[c.analystName] = { count: 0, completed: 0 };
    acc[c.analystName].count += 1;
    if (c.progress === 100) acc[c.analystName].completed += 1;
    return acc;
  }, {});

  return (
    <div className="animate-fadeIn">
      <div className="mb-8">
        <h2 className="text-2xl font-bold text-slate-800">Relatório de Desempenho</h2>
        <p className="text-slate-500">Visão geral da operação e status das cotas de consórcio.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center mb-4">
            <i className="fa-solid fa-users text-xl"></i>
          </div>
          <p className="text-slate-500 text-sm font-medium">Total de Clientes</p>
          <p className="text-3xl font-bold text-slate-800">{totalClients}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center mb-4">
            <i className="fa-solid fa-check-double text-xl"></i>
          </div>
          <p className="text-slate-500 text-sm font-medium">Propostas Concluídas</p>
          <p className="text-3xl font-bold text-slate-800">{completedProposals}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="w-12 h-12 bg-amber-50 text-amber-600 rounded-xl flex items-center justify-center mb-4">
            <i className="fa-solid fa-file-circle-exclamation text-xl"></i>
          </div>
          <p className="text-slate-500 text-sm font-medium">Docs Pendentes</p>
          <p className="text-3xl font-bold text-slate-800">{pendingDocs}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center mb-4">
            <i className="fa-solid fa-chart-line text-xl"></i>
          </div>
          <p className="text-slate-500 text-sm font-medium">Média de Progresso</p>
          <p className="text-3xl font-bold text-slate-800">{averageProgress.toFixed(0)}%</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Analyst Chart */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <i className="fa-solid fa-user-tie text-indigo-500"></i>
            Produtividade por Analista
          </h3>
          <div className="space-y-6">
            {Object.keys(analystStats).map((name) => {
              const stat = analystStats[name];
              const perc = (stat.completed / stat.count) * 100;
              return (
                <div key={name}>
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-sm font-semibold text-slate-700">{name}</span>
                    <span className="text-xs text-slate-500">{stat.completed}/{stat.count} propostas concluídas</span>
                  </div>
                  <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-indigo-600 rounded-full transition-all duration-1000"
                      style={{ width: `${perc}%` }}
                    ></div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Client Status List */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 overflow-hidden">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <i className="fa-solid fa-list-check text-indigo-500"></i>
            Status Geral por Cota
          </h3>
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead>
                <tr className="text-slate-400 border-b border-slate-100">
                  <th className="pb-3 font-medium">Cliente</th>
                  <th className="pb-3 font-medium">Grupo/Cota</th>
                  <th className="pb-3 font-medium">Progresso</th>
                  <th className="pb-3 font-medium">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {clients.map(client => (
                  <tr key={client.id} className="hover:bg-slate-50 transition-colors">
                    <td className="py-4 font-medium text-slate-700">{client.name}</td>
                    <td className="py-4 text-slate-500">{client.group} / {client.quota}</td>
                    <td className="py-4">
                      <div className="flex items-center gap-2">
                        <div className="w-16 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                          <div className="h-full bg-indigo-500" style={{ width: `${client.progress}%` }}></div>
                        </div>
                        <span className="text-xs text-slate-400">{client.progress}%</span>
                      </div>
                    </td>
                    <td className="py-4">
                      <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${
                        client.progress === 100 ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'
                      }`}>
                        {client.progress === 100 ? 'Finalizado' : 'Em Análise'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

