import React, { useState, useEffect } from 'react';
import { Client, DocumentStatus, DocumentType } from '../types';
import { classifyDocument } from '../services/geminiService';

interface ClientDetailsProps {
  client: Client;
  onUpdateDocument: (docId: string, updates: any) => void;
  onUpdateClientInfo: (updates: Partial<Client>) => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, onUpdateDocument, onUpdateClientInfo }) => {
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState({
    name: '',
    cpf: '',
    group: '',
    quota: '',
    consortiumType: ''
  });

  // Sync edit form when client changes or editing starts
  useEffect(() => {
    setEditForm({
      name: client.name,
      cpf: client.cpf,
      group: client.group,
      quota: client.quota,
      consortiumType: client.consortiumType
    });
  }, [client, isEditing]);

  const handleSaveInfo = () => {
    onUpdateClientInfo(editForm);
    setIsEditing(false);
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, targetDocId: string) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(targetDocId);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);
      const targetDoc = client.documents.find(d => d.id === targetDocId);

      if (targetDoc) {
        const isMatch = result.type === targetDoc.type;

        onUpdateDocument(targetDocId, {
          status: DocumentStatus.UPLOADED,
          fileName: file.name,
          uploadDate: new Date().toISOString().split('T')[0],
          confidence: result.confidence
        });

        if (!isMatch && result.type !== DocumentType.UNKNOWN) {
          alert(`Aviso: O documento enviado parece ser "${result.type}", mas você o enviou no campo de "${targetDoc.type}". Por favor, verifique.`);
        }
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn">
      {/* Profile Header */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative">
        <div className="flex items-center gap-5 w-full">
          <div className="w-16 h-16 bg-slate-50 rounded-2xl flex-shrink-0 flex items-center justify-center text-indigo-500 text-2xl border border-slate-200 shadow-inner">
            <i className="fa-solid fa-user-check"></i>
          </div>

          <div className="flex-grow">
            {!isEditing ? (
              <>
                <div className="flex items-center gap-3">
                  <h2 className="text-2xl font-bold text-slate-800">{client.name}</h2>
                  <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-full uppercase border border-indigo-100">
                    {client.consortiumType}
                  </span>
                  <button 
                    onClick={() => setIsEditing(true)}
                    className="ml-2 p-1 text-slate-300 hover:text-indigo-600 transition-colors"
                    title="Editar informações"
                  >
                    <i className="fa-solid fa-pen-to-square"></i>
                  </button>
                </div>

                <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-sm text-slate-500">
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-id-card text-xs text-slate-400"></i> {client.cpf}</span>
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-tags text-xs text-slate-400"></i> Grupo: <b className="text-slate-700">{client.group}</b> / Cota: <b className="text-slate-700">{client.quota}</b></span>
                </div>
              </>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 w-full pr-12">
                <div className="col-span-1 md:col-span-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Nome Completo</label>
                  <input 
                    type="text" 
                    className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    value={editForm.name}
                    onChange={(e) => setEditForm({...editForm, name: e.target.value})}
                  />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">CPF</label>
                  <input 
                    type="text" 
                    className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    value={editForm.cpf}
