export type ViewType = 'dashboard' | 'reports';

const App: React.FC = () => {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeView, setActiveView] = useState<ViewType>('dashboard');

  const selectedClient = clients.find(c => c.id === selectedClientId);

  const calculateProgress = (docs: ClientDocument[]) => {
    const requiredTypes = [DocumentType.ID, DocumentType.RESIDENCE, DocumentType.INCOME, DocumentType.CONTRACT];
    const completedTypes = requiredTypes.filter(type => 
      docs.some(doc => doc.type === type && doc.status === DocumentStatus.UPLOADED)
    );
    return Math.round((completedTypes.length / requiredTypes.length) * 100);
  };

  const handleAddDocument = (clientId: string, newDoc: ClientDocument) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = [...client.documents, newDoc];
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs) 
      };
    }));
  };

  const handleRemoveDocument = (clientId: string, docId: string) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = client.documents.filter(d => d.id !== docId);
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs) 
      };
    }));
  };

  const handleUpdateClientInfo = (clientId: string, updates: Partial<Client>) => {
    setClients(prev => prev.map(client => 
      client.id === clientId ? { ...client, ...updates } : client
    ));
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.cpf.includes(searchTerm) ||
    c.group.includes(searchTerm) ||
    c.quota.includes(searchTerm) ||
    c.analystName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header activeView={activeView} onViewChange={setActiveView} />

      <main className="flex-grow container mx-auto px-4 py-8">
        {activeView === 'dashboard' ? (
          <div className="flex flex-col lg:flex-row gap-8 animate-fadeIn">
            <div className="w-full lg:w-1/3 xl:w-1/4">
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="p-4 border-b border-slate-100">
                  <div className="relative">
                    <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
                    <input 
                      type="text" 
                      placeholder="Buscar nome, CPF, Grupo ou Cota..."
                      className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                </div>
                <ClientList 
                  clients={filteredClients} 
                  selectedId={selectedClientId} 
                  onSelect={setSelectedClientId} 
                />
              </div>
            </div>

            <div className="w-full lg:w-2/3 xl:w-3/4">
              {selectedClient ? (
                <ClientDetails 
                  client={selectedClient} 
                  onAddDocument={(newDoc) => handleAddDocument(selectedClient.id, newDoc)}
                  onRemoveDocument={(docId) => handleRemoveDocument(selectedClient.id, docId)}
                  onUpdateClientInfo={(updates) => handleUpdateClientInfo(selectedClient.id, updates)}
                />
              ) : (
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-12 flex flex-col items-center justify-center text-center">
                  <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600 mb-6">
                    <i className="fa-solid fa-users text-3xl"></i>
                  </div>
                  <h2 className="text-xl font-semibold text-slate-800 mb-2">Selecione um Cliente</h2>
                  <p className="text-slate-500 max-w-xs mx-auto">
                    Escolha um cliente da lista ao lado para gerenciar seus documentos e acompanhar o status da proposta.
                  </p>
                </div>
              )}
            </div>
          </div>
        ) : (
          <Reports clients={clients} />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 text-center text-slate-400 text-sm">
        <p>&copy; 2024 DocFlow Consórcios - Tecnologia para Gestão Documental</p>
      </footer>
    </div>
  );
};

