import React, { useState, useEffect } from 'react';
import { Client, DocumentStatus, DocumentType, ClientDocument } from '../types';
import { classifyDocument } from '../services/geminiService';

interface ClientDetailsProps {
  client: Client;
  onAddDocument: (newDoc: ClientDocument) => void;
  onRemoveDocument: (docId: string) => void;
  onUpdateClientInfo: (updates: Partial<Client>) => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, onAddDocument, onRemoveDocument, onUpdateClientInfo }) => {
  const [isProcessing, setIsProcessing] = useState<DocumentType | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [viewingDoc, setViewingDoc] = useState<ClientDocument | null>(null);
  const [editForm, setEditForm] = useState({
    name: '',
    cpf: '',
    group: '',
    quota: '',
    consortiumType: ''
  });

  const categories = [
    DocumentType.ID,
    DocumentType.RESIDENCE,
    DocumentType.INCOME,
    DocumentType.CONTRACT
  ];

  useEffect(() => {
    setEditForm({
      name: client.name,
      cpf: client.cpf,
      group: client.group,
      quota: client.quota,
      consortiumType: client.consortiumType
    });
  }, [client, isEditing]);

  const handleSaveInfo = () => {
    onUpdateClientInfo(editForm);
    setIsEditing(false);
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, category: DocumentType) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(category);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);

      const newDoc: ClientDocument = {
        id: Math.random().toString(36).substr(2, 9),
        type: category,
        status: DocumentStatus.UPLOADED,
        fileName: file.name,
        fileData: reader.result as string,
        uploadDate: new Date().toISOString().split('T')[0],
        confidence: result.confidence
      };

      onAddDocument(newDoc);

      if (result.type !== category && result.type !== DocumentType.UNKNOWN) {
        alert(`Aviso: O documento enviado foi identificado como "${result.type}", mas foi adicionado em "${category}".`);
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn pb-20">
      {/* Profile Header */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative">
        <div className="flex items-center gap-5 w-full">
          <div className="w-16 h-16 bg-slate-50 rounded-2xl flex-shrink-0 flex items-center justify-center text-indigo-500 text-2xl border border-slate-200 shadow-inner">
            <i className="fa-solid fa-user-check"></i>
          </div>

          <div className="flex-grow">
            {!isEditing ? (
              <>
                <div className="flex items-center gap-3">
                  <h2 className="text-2xl font-bold text-slate-800">{client.name}</h2>
                  <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-full uppercase border border-indigo-100">
                    {client.consortiumType}
                  </span>
                  <button 
                    onClick={() => setIsEditing(true)}
                    className="ml-2 p-1 text-slate-300 hover:text-indigo-600 transition-colors"
                  >
                    <i className="fa-solid fa-pen-to-square"></i>
                  </button>
                </div>

                <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-sm text-slate-500">
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-id-card text-xs text-slate-400"></i> {client.cpf}</span>
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-tags text-xs text-slate-400"></i> Grupo: <b className="text-slate-700">{client.group}</b> / Cota: <b className="text-slate-700">{client.quota}</b></span>
                </div>
              </>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 w-full pr-12">
                <div className="col-span-1 md:col-span-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Nome Completo</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.name} onChange={(e) => setEditForm({...editForm, name: e.target.value})} />
                </div>
                <div><label className="text-[10px] font-bold text-slate-400 uppercase">CPF</label><input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.cpf} onChange={(e) => setEditForm({...editForm, cpf: e.target.value})} /></div>
                <div><label className="text-[10px] font-bold text-slate-400 uppercase">Grupo</label><input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.group} onChange={(e) => setEditForm({...editForm, group: e.target.value})} /></div>
                <div><label className="text-[10px] font-bold text-slate-400 uppercase">Cota</label><input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.quota} onChange={(e) => setEditForm({...editForm, quota: e.target.value})} /></div>
                <div className="flex items-end gap-2">
                  <button onClick={handleSaveInfo} className="bg-indigo-600 text-white px-4 py-1.5 rounded text-sm font-bold">Salvar</button>
                  <button onClick={() => setIsEditing(false)} className="bg-slate-100 text-slate-500 px-4 py-1.5 rounded text-sm font-medium">Cancelar</button>
                </div>
              </div>
            )}
            <div className="mt-3 flex items-center gap-2">
               <img src={`https://ui-avatars.com/api/?name=${encodeURIComponent(client.analystName)}&background=6366f1&color=fff`} className="w-6 h-6 rounded-full" alt="Analyst" />
               <span className="text-xs text-slate-500">Analista: <strong className="text-slate-800">{client.analystName}</strong></span>
            </div>
          </div>
        </div>

        {!isEditing && (
          <div className="w-full md:w-auto flex flex-col items-end gap-1 bg-slate-50 p-4 rounded-xl border border-slate-100">
            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Status da Documentação</span>
            <div className="w-full md:w-48 h-2.5 bg-slate-200 rounded-full overflow-hidden mt-1">
              <div className={`h-full transition-all duration-1000 ${client.progress === 100 ? 'bg-emerald-500' : 'bg-indigo-600'}`} style={{ width: `${client.progress}%` }}></div>
            </div>
            <span className={`text-sm font-bold mt-1 ${client.progress === 100 ? 'text-emerald-600' : 'text-indigo-600'}`}>{client.progress}% Concluído</span>
          </div>
        )}
      </div>

      {/* Document Categories */}
      <div className="grid grid-cols-1 gap-6">
        {categories.map((category) => {
          const categoryDocs = client.documents.filter(d => d.type === category);
          const isComplete = categoryDocs.length > 0;

          return (
            <div key={category} className={`bg-white rounded-2xl border p-6 transition-all shadow-sm ${isComplete ? 'border-emerald-100' : 'border-slate-200'}`}>
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl ${isComplete ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                    <i className={`fa-solid ${
                      category === DocumentType.ID ? 'fa-address-card' :
                      category === DocumentType.RESIDENCE ? 'fa-house' :
                      category === DocumentType.INCOME ? 'fa-receipt' : 'fa-file-signature'
                    }`}></i>
                  </div>
                  <div>
                    <h3 className="text-lg font-bold text-slate-800 leading-tight">{category}</h3>
                    <p className="text-xs text-slate-400 font-medium">
                      {isComplete ? `${categoryDocs.length} documento(s) enviado(s)` : 'Nenhum documento enviado'}
                    </p>
                  </div>
                </div>

                <label className="flex items-center justify-center gap-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 px-5 py-2.5 rounded-xl text-sm font-bold cursor-pointer transition-all active:scale-95 border border-indigo-100">
                  {isProcessing === category ? (
                    <i className="fa-solid fa-circle-notch animate-spin"></i>
                  ) : (
                    <i className="fa-solid fa-plus"></i>
                  )}
                  <span>Adicionar Documento</span>
                  <input type="file" className="hidden" accept="image/*,application/pdf" onChange={(e) => handleFileUpload(e, category)} disabled={isProcessing !== null} />
                </label>
              </div>

              {categoryDocs.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {categoryDocs.map((doc) => (
                    <div key={doc.id} className="group relative bg-slate-50 border border-slate-100 rounded-xl p-3 flex flex-col gap-2 hover:border-indigo-200 transition-all">
                      <div className="flex items-start justify-between">
                        <div className="flex items-center gap-2 overflow-hidden">
                          <i className="fa-solid fa-file-pdf text-red-500 text-lg flex-shrink-0"></i>
                          <div className="overflow-hidden">
                            <p className="text-xs font-bold text-slate-700 truncate">{doc.fileName}</p>
                            <p className="text-[10px] text-slate-400">{doc.uploadDate}</p>
                          </div>
                        </div>
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => setViewingDoc(doc)} className="p-1.5 text-slate-400 hover:text-indigo-600" title="Visualizar"><i className="fa-solid fa-eye text-xs"></i></button>
                          <button onClick={() => onRemoveDocument(doc.id)} className="p-1.5 text-slate-400 hover:text-red-500" title="Excluir"><i className="fa-solid fa-trash text-xs"></i></button>
                        </div>
                      </div>
                      {doc.confidence && (
                        <div className="flex items-center gap-1.5 text-[9px] text-indigo-500 font-bold bg-indigo-50/50 p-1 rounded">
                          <i className="fa-solid fa-robot"></i>
                          <span>IA: {(doc.confidence * 100).toFixed(0)}% de precisão</span>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <div className="border-2 border-dashed border-slate-100 rounded-xl py-8 text-center bg-slate-50/30">
                  <i className="fa-solid fa-file-arrow-up text-slate-200 text-3xl mb-2"></i>
                  <p className="text-xs text-slate-400">Obrigatório para conclusão da proposta</p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Action Bar */}
      <div className="fixed bottom-8 right-8 left-8 lg:left-1/3 xl:left-1/4 z-40">
        <div className="bg-slate-900 rounded-2xl text-white p-5 flex flex-col sm:flex-row items-center justify-between gap-4 shadow-2xl border border-slate-700 max-w-5xl mx-auto">
          <div className="flex items-center gap-4">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${client.progress === 100 ? 'bg-emerald-500' : 'bg-slate-800 text-slate-500'}`}>
              <i className={`fa-solid ${client.progress === 100 ? 'fa-check' : 'fa-clock'}`}></i>
            </div>
            <div>
              <p className="font-bold text-sm">Status da Proposta</p>
              <p className="text-xs text-slate-400">{client.progress === 100 ? 'Documentação completa' : 'Pendente de documentos obrigatórios'}</p>
            </div>
          </div>
          <button disabled={client.progress < 100} className={`px-8 py-3 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2 ${client.progress === 100 ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-800 text-slate-600 cursor-not-allowed'}`}>
            <i className="fa-solid fa-paper-plane"></i>
            Finalizar Processo
          </button>
        </div>
      </div>

      {/* Document Viewer Modal */}
      {viewingDoc && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center">
                  <i className="fa-solid fa-file-invoice"></i>
                </div>
                <div>
                  <h3 className="font-bold text-slate-800">{viewingDoc.type}</h3>
                  <p className="text-xs text-slate-400">{viewingDoc.fileName}</p>
                </div>
              </div>
              <button onClick={() => setViewingDoc(null)} className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-slate-600 transition-colors">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <div className="flex-grow bg-slate-100 p-8 flex items-center justify-center overflow-auto">
              {viewingDoc.fileData ? (
                <img src={viewingDoc.fileData} alt="Documento" className="max-w-full rounded-lg shadow-lg border border-white" />
              ) : (
                <div className="text-center text-slate-400">
                  <i className="fa-solid fa-eye-slash text-5xl mb-4 opacity-20"></i>
                  <p>Visualização indisponível para este arquivo mock.</p>
                </div>
              )}
            </div>
            <div className="p-6 border-t border-slate-100 flex justify-end gap-3">
               <button onClick={() => setViewingDoc(null)} className="px-6 py-2.5 bg-slate-100 text-slate-600 font-bold rounded-xl text-sm">Fechar</button>
               <button className="px-6 py-2.5 bg-indigo-600 text-white font-bold rounded-xl text-sm flex items-center gap-2">
                 <i className="fa-solid fa-download"></i> Baixar Arquivo
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

