                <label className="flex items-center justify-center gap-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 px-5 py-2.5 rounded-xl text-sm font-bold cursor-pointer transition-all active:scale-95 border border-indigo-100">
                  {isProcessing === category ? (
                    <i className="fa-solid fa-circle-notch animate-spin"></i>
                  ) : (
                    <i className="fa-solid fa-plus"></i>
                  )}
                  <span>Adicionar Documento</span>
                  <input type="file" className="hidden" accept="image/*,application/pdf" onChange={(e) => handleFileUpload(e, category)} disabled={isProcessing !== null} />
