            <div>
              <p className="font-bold text-sm">Status da Proposta</p>
              <p className="text-xs text-slate-400">{client.progress === 100 ? 'Documentação completa' : 'Pendente de documentos obrigatórios'}</p>
            </div>
          </div>
          <button disabled={client.progress < 100} className={`px-8 py-3 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2 ${client.progress === 100 ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-800 text-slate-600 cursor-not-allowed'}`}>
            <i className="fa-solid fa-paper-plane"></i>
            Finalizar Processo
          </button>
