                <div>
                  <h3 className="font-bold text-slate-800">{viewingDoc.type}</h3>
                  <p className="text-xs text-slate-400">{viewingDoc.fileName}</p>
                </div>
              </div>
              <button onClick={() => setViewingDoc(null)} className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-slate-600 transition-colors">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <div className="flex-grow bg-slate-100 p-8 flex items-center justify-center overflow-auto">
              {viewingDoc.fileData ? (
                <img src={viewingDoc.fileData} alt="Documento" className="max-w-full rounded-lg shadow-lg border border-white" />
              ) : (
                <div className="text-center text-slate-400">
                  <i className="fa-solid fa-eye-slash text-5xl mb-4 opacity-20"></i>
                  <p>Visualização indisponível para este arquivo mock.</p>
                </div>
              )}
            </div>
            <div className="p-6 border-t border-slate-100 flex justify-end gap-3">
               <button onClick={() => setViewingDoc(null)} className="px-6 py-2.5 bg-slate-100 text-slate-600 font-bold rounded-xl text-sm">Fechar</button>
               <button className="px-6 py-2.5 bg-indigo-600 text-white font-bold rounded-xl text-sm flex items-center gap-2">
                 <i className="fa-solid fa-download"></i> Baixar Arquivo
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

