export type ViewType = 'dashboard' | 'reports';

const App: React.FC = () => {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeView, setActiveView] = useState<ViewType>('dashboard');

  const selectedClient = clients.find(c => c.id === selectedClientId);

  const calculateProgress = (docs: ClientDocument[]) => {
    const requiredTypes = [DocumentType.ID, DocumentType.RESIDENCE, DocumentType.INCOME, DocumentType.CONTRACT];
    const completedTypes = requiredTypes.filter(type => 
      docs.some(doc => doc.type === type && doc.status === DocumentStatus.UPLOADED)
    );
    return Math.round((completedTypes.length / requiredTypes.length) * 100);
  };

  const handleAddDocument = (clientId: string, newDoc: ClientDocument) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = [...client.documents, newDoc];
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs) 
      };
    }));
  };

  const handleRemoveDocument = (clientId: string, docId: string) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = client.documents.filter(d => d.id !== docId);
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs) 
      };
    }));
  };

  const handleUpdateClientInfo = (clientId: string, updates: Partial<Client>) => {
    setClients(prev => prev.map(client => 
      client.id === clientId ? { ...client, ...updates } : client
    ));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(client => client.id !== clientId));
    setSelectedClientId(null);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.cpf.includes(searchTerm) ||
    c.group.includes(searchTerm) ||
    c.quota.includes(searchTerm) ||
    c.analystName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.analystContemplation.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header activeView={activeView} onViewChange={setActiveView} />

      <main className="flex-grow container mx-auto px-4 py-8">
        {activeView === 'dashboard' ? (
          <div className="flex flex-col lg:flex-row gap-8 animate-fadeIn">
            <div className="w-full lg:w-1/3 xl:w-1/4">
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="p-4 border-b border-slate-100">
                  <div className="relative">
                    <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
                    <input 
                      type="text" 
                      placeholder="Buscar nome, CPF, Grupo ou Cota..."
                      className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                </div>
                <ClientList 
                  clients={filteredClients} 
                  selectedId={selectedClientId} 
                  onSelect={setSelectedClientId} 
                />
              </div>
            </div>

            <div className="w-full lg:w-2/3 xl:w-3/4">
              {selectedClient ? (
                <ClientDetails 
                  client={selectedClient} 
                  onAddDocument={(newDoc) => handleAddDocument(selectedClient.id, newDoc)}
                  onRemoveDocument={(docId) => handleRemoveDocument(selectedClient.id, docId)}
                  onUpdateClientInfo={(updates) => handleUpdateClientInfo(selectedClient.id, updates)}
                  onDeleteClient={() => handleDeleteClient(selectedClient.id)}
                />
              ) : (
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-12 flex flex-col items-center justify-center text-center">
                  <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600 mb-6">
                    <i className="fa-solid fa-users text-3xl"></i>
                  </div>
                  <h2 className="text-xl font-semibold text-slate-800 mb-2">Selecione um Cliente</h2>
                  <p className="text-slate-500 max-w-xs mx-auto">
                    Escolha um cliente da lista ao lado para gerenciar seus documentos e acompanhar o status da proposta.
                  </p>
                </div>
              )}
            </div>
          </div>
        ) : (
          <Reports clients={clients} />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 text-center text-slate-400 text-sm">
        <p>&copy; 2024 DocFlow Consórcios - Tecnologia para Gestão Documental</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Client, DocumentStatus, DocumentType, ClientDocument } from '../types';
import { classifyDocument } from '../services/geminiService';

interface ClientDetailsProps {
  client: Client;
  onAddDocument: (newDoc: ClientDocument) => void;
  onRemoveDocument: (docId: string) => void;
  onUpdateClientInfo: (updates: Partial<Client>) => void;
  onDeleteClient: () => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, onAddDocument, onRemoveDocument, onUpdateClientInfo, onDeleteClient }) => {
  const [isProcessing, setIsProcessing] = useState<DocumentType | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [viewingDoc, setViewingDoc] = useState<ClientDocument | null>(null);
  const [editForm, setEditForm] = useState({
    name: '',
    cpf: '',
    group: '',
    quota: '',
    consortiumType: '',
    analystName: '',
    analystContemplation: ''
  });

  const categories = [
    DocumentType.ID,
    DocumentType.RESIDENCE,
    DocumentType.INCOME,
    DocumentType.CONTRACT
  ];

  const consortiumOptions = ['Imobiliário', 'Automotivo', 'Pesados', 'Serviços', 'Motos'];

  useEffect(() => {
    setEditForm({
      name: client.name,
      cpf: client.cpf,
      group: client.group,
      quota: client.quota,
      consortiumType: client.consortiumType,
      analystName: client.analystName,
      analystContemplation: client.analystContemplation
    });
  }, [client, isEditing]);

  const handleSaveInfo = () => {
    onUpdateClientInfo(editForm);
    setIsEditing(false);
  };

  const handleDeleteConfirm = () => {
    if (window.confirm(`Tem certeza que deseja excluir permanentemente o cadastro de ${client.name}? Esta ação não pode ser desfeita.`)) {
      onDeleteClient();
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, category: DocumentType) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(category);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);

      const newDoc: ClientDocument = {
        id: Math.random().toString(36).substr(2, 9),
        type: category,
        status: DocumentStatus.UPLOADED,
        fileName: file.name,
        fileData: reader.result as string,
        uploadDate: new Date().toISOString().split('T')[0],
        confidence: result.confidence
      };

      onAddDocument(newDoc);

      if (result.type !== category && result.type !== DocumentType.UNKNOWN) {
        alert(`Aviso: O documento enviado foi identificado como "${result.type}", mas foi adicionado em "${category}".`);
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn pb-20">
      {/* Profile Header */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative">
        <div className="flex items-center gap-5 w-full">
          <div className="w-16 h-16 bg-slate-50 rounded-2xl flex-shrink-0 flex items-center justify-center text-indigo-500 text-2xl border border-slate-200 shadow-inner relative">
            <i className="fa-solid fa-user-check"></i>
          </div>

          <div className="flex-grow">
            {!isEditing ? (
              <>
                <div className="flex items-center flex-wrap gap-3">
                  <h2 className="text-2xl font-bold text-slate-800">{client.name}</h2>
                  <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-full uppercase border border-indigo-100">
                    {client.consortiumType}
                  </span>
                  <div className="flex items-center gap-1.5 px-2 py-0.5 bg-amber-50 text-amber-700 text-[10px] font-bold rounded-full uppercase border border-amber-100">
                    <i className="fa-solid fa-star text-[8px]"></i>
                    Contemplação: {client.analystContemplation}
                  </div>
                  <button 
                    onClick={() => setIsEditing(true)}
                    className="ml-2 p-1 text-slate-300 hover:text-indigo-600 transition-colors"
                    title="Editar informações"
                  >
                    <i className="fa-solid fa-pen-to-square"></i>
                  </button>
                </div>

                <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-sm text-slate-500">
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-id-card text-xs text-slate-400"></i> {client.cpf}</span>
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-tags text-xs text-slate-400"></i> Grupo: <b className="text-slate-700">{client.group}</b> / Cota: <b className="text-slate-700">{client.quota}</b></span>
                </div>

                <div className="mt-3 flex items-center gap-4">
                  <div className="flex items-center gap-2">
                    <img src={`https://ui-avatars.com/api/?name=${encodeURIComponent(client.analystName)}&background=6366f1&color=fff`} className="w-6 h-6 rounded-full" alt="Analyst" />
                    <span className="text-xs text-slate-500">Cadastro: <strong className="text-slate-800">{client.analystName}</strong></span>
                  </div>
                  <div className="flex items-center gap-2 border-l border-slate-100 pl-4">
                    <img src={`https://ui-avatars.com/api/?name=${encodeURIComponent(client.analystContemplation)}&background=f59e0b&color=fff`} className="w-6 h-6 rounded-full" alt="Contemplation Analyst" />
                    <span className="text-xs text-slate-500">Contemplação: <strong className="text-slate-800">{client.analystContemplation}</strong></span>
                  </div>
                </div>
              </>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3 w-full pr-12">
                <div className="col-span-1 md:col-span-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Nome Completo</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.name} onChange={(e) => setEditForm({...editForm, name: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">CPF</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.cpf} onChange={(e) => setEditForm({...editForm, cpf: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Tipo de Consórcio</label>
                  <select 
                    className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" 
                    value={editForm.consortiumType} 
                    onChange={(e) => setEditForm({...editForm, consortiumType: e.target.value})}
                  >
                    {consortiumOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Grupo</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.group} onChange={(e) => setEditForm({...editForm, group: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Cota</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.quota} onChange={(e) => setEditForm({...editForm, quota: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Analista Cadastro</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.analystName} onChange={(e) => setEditForm({...editForm, analystName: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Analista Contemplação</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm border-amber-200" value={editForm.analystContemplation} onChange={(e) => setEditForm({...editForm, analystContemplation: e.target.value})} />
                </div>
                <div className="flex items-end gap-2 col-span-full justify-between mt-4 pt-4 border-t border-slate-100">
                  <button 
                    onClick={handleDeleteConfirm}
                    className="bg-red-50 text-red-600 px-4 py-1.5 rounded text-sm font-bold hover:bg-red-100 transition-all flex items-center gap-2"
                  >
                    <i className="fa-solid fa-trash-can"></i>
                    Excluir Cadastro
                  </button>
                  <div className="flex items-center gap-2">
                    <button onClick={() => setIsEditing(false)} className="bg-slate-100 text-slate-500 px-4 py-1.5 rounded text-sm font-medium hover:bg-slate-200 transition-all">Cancelar</button>
                    <button onClick={handleSaveInfo} className="bg-indigo-600 text-white px-6 py-1.5 rounded text-sm font-bold shadow-md hover:bg-indigo-700 transition-all">Salvar Alterações</button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {!isEditing && (
          <div className="w-full md:w-auto flex flex-col items-end gap-1 bg-slate-50 p-4 rounded-xl border border-slate-100">
            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Status da Documentação</span>
            <div className="w-full md:w-48 h-2.5 bg-slate-200 rounded-full overflow-hidden mt-1">
              <div className={`h-full transition-all duration-1000 ${client.progress === 100 ? 'bg-emerald-500' : 'bg-indigo-600'}`} style={{ width: `${client.progress}%` }}></div>
            </div>
            <span className={`text-sm font-bold mt-1 ${client.progress === 100 ? 'text-emerald-600' : 'text-indigo-600'}`}>{client.progress}% Concluído</span>
          </div>
        )}
      </div>

      {/* Document Categories */}
      <div className="grid grid-cols-1 gap-6">
        {categories.map((category) => {
          const categoryDocs = client.documents.filter(d => d.type === category);
          const isComplete = categoryDocs.length > 0;

          return (
            <div key={category} className={`bg-white rounded-2xl border p-6 transition-all shadow-sm ${isComplete ? 'border-emerald-100' : 'border-slate-200'}`}>
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl ${isComplete ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                    <i className={`fa-solid ${
                      category === DocumentType.ID ? 'fa-address-card' :
                      category === DocumentType.RESIDENCE ? 'fa-house' :
                      category === DocumentType.INCOME ? 'fa-receipt' : 'fa-file-signature'
                    }`}></i>
                  </div>
                  <div>
                    <h3 className="text-lg font-bold text-slate-800 leading-tight">{category}</h3>
                    <p className="text-xs text-slate-400 font-medium">
                      {isComplete ? `${categoryDocs.length} documento(s) enviado(s)` : 'Nenhum documento enviado'}
                    </p>
                  </div>
                </div>

                <label className="flex items-center justify-center gap-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 px-5 py-2.5 rounded-xl text-sm font-bold cursor-pointer transition-all active:scale-95 border border-indigo-100">
                  {isProcessing === category ? (
                    <i className="fa-solid fa-circle-notch animate-spin"></i>
                  ) : (
                    <i className="fa-solid fa-plus"></i>
                  )}
                  <span>Adicionar Documento</span>
                  <input type="file" className="hidden" accept="image/*,application/pdf" onChange={(e) => handleFileUpload(e, category)} disabled={isProcessing !== null} />
                </label>
              </div>

              {categoryDocs.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {categoryDocs.map((doc) => (
                    <div key={doc.id} className="group relative bg-slate-50 border border-slate-100 rounded-xl p-3 flex flex-col gap-2 hover:border-indigo-200 transition-all">
                      <div className="flex items-start justify-between">
                        <div className="flex items-center gap-2 overflow-hidden">
                          <i className="fa-solid fa-file-pdf text-red-500 text-lg flex-shrink-0"></i>
                          <div className="overflow-hidden">
                            <p className="text-xs font-bold text-slate-700 truncate">{doc.fileName}</p>
                            <p className="text-[10px] text-slate-400">{doc.uploadDate}</p>
                          </div>
                        </div>
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => setViewingDoc(doc)} className="p-1.5 text-slate-400 hover:text-indigo-600" title="Visualizar"><i className="fa-solid fa-eye text-xs"></i></button>
                          <button onClick={() => onRemoveDocument(doc.id)} className="p-1.5 text-slate-400 hover:text-red-500" title="Excluir"><i className="fa-solid fa-trash text-xs"></i></button>
                        </div>
                      </div>
                      {doc.confidence && (
                        <div className="flex items-center gap-1.5 text-[9px] text-indigo-500 font-bold bg-indigo-50/50 p-1 rounded">
                          <i className="fa-solid fa-robot"></i>
                          <span>IA: {(doc.confidence * 100).toFixed(0)}% de precisão</span>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <div className="border-2 border-dashed border-slate-100 rounded-xl py-8 text-center bg-slate-50/30">
                  <i className="fa-solid fa-file-arrow-up text-slate-200 text-3xl mb-2"></i>
                  <p className="text-xs text-slate-400">Obrigatório para conclusão da proposta</p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Action Bar */}
      <div className="fixed bottom-8 right-8 left-8 lg:left-1/3 xl:left-1/4 z-40">
        <div className="bg-slate-900 rounded-2xl text-white p-5 flex flex-col sm:flex-row items-center justify-between gap-4 shadow-2xl border border-slate-700 max-w-5xl mx-auto">
          <div className="flex items-center gap-4">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${client.progress === 100 ? 'bg-emerald-500' : 'bg-slate-800 text-slate-500'}`}>
              <i className={`fa-solid ${client.progress === 100 ? 'fa-check' : 'fa-clock'}`}></i>
            </div>
            <div>
              <p className="font-bold text-sm">Status da Proposta</p>
              <p className="text-xs text-slate-400">{client.progress === 100 ? 'Documentação completa' : 'Pendente de documentos obrigatórios'}</p>
