          <button 
            disabled={client.progress < 100 || isFinalizing} 
            onClick={handleFinalizeProcess}
            className={`px-8 py-3 rounded-xl font-bold transition-all shadow-lg flex items-center gap-3 relative overflow-hidden ${
              client.progress === 100 
