    cpf: '',
    group: '',
    quota: '',
    consortiumType: '',
    analystName: '',
    analystEmail: '',
    analystContemplation: ''
  });

  const categories = [
    DocumentType.ID,
    DocumentType.RESIDENCE,
    DocumentType.INCOME,
    DocumentType.CONTRACT
  ];

  const consortiumOptions = ['Imobiliário', 'Automotivo', 'Pesados', 'Serviços', 'Motos'];

  useEffect(() => {
    setEditForm({
      name: client.name,
      cpf: client.cpf,
      group: client.group,
      quota: client.quota,
      consortiumType: client.consortiumType,
      analystName: client.analystName,
      analystEmail: client.analystEmail || `${client.analystName.toLowerCase().replace(' ', '.')}@consorcioancora.com.br`,
      analystContemplation: client.analystContemplation
    });
  }, [client, isEditing]);

  const handleSaveInfo = () => {
    onUpdateClientInfo(editForm);
    setIsEditing(false);
  };

  const handleDeleteConfirm = () => {
    if (window.confirm(`Tem certeza que deseja excluir permanentemente o cadastro de ${client.name}? Esta ação não pode ser desfeita.`)) {
      onDeleteClient();
    }
  };

  const handleFinalizeProcess = async () => {
    if (client.progress < 100) return;

    setIsFinalizing(true);

    try {
      // 1. Create a ZIP file of all documents
      const zip = new JSZip();
      const folderName = `Documentos_${client.name.replace(/\s+/g, '_')}`;
      const folder = zip.folder(folderName);

      if (folder) {
        client.documents.forEach((doc) => {
          if (doc.fileData) {
            // Extract base64 content from Data URL
            const base64Content = doc.fileData.split(',')[1];
            folder.file(doc.fileName || `${doc.type}.jpg`, base64Content, { base64: true });
          }
        });
      }

      // 2. Generate and trigger download
      const content = await zip.generateAsync({ type: 'blob' });
      const downloadLink = document.createElement('a');
      downloadLink.href = URL.createObjectURL(content);
      downloadLink.download = `${folderName}.zip`;
      document.body.appendChild(downloadLink);
      downloadLink.click();
      document.body.removeChild(downloadLink);

      // 3. Prepare Email Content for Outlook
      // Note: mailto doesn't support direct attachments, so we instruct the user to attach the downloaded ZIP.
      const subject = encodeURIComponent(`[DOC ÂNCORA] Documentação Completa - ${client.name} (Grupo ${client.group} / Cota ${client.quota})`);

      const body = encodeURIComponent(
        `Prezado(a) ${client.analystName},\r\n\r\n` +
        `A documentação do cliente ${client.name} foi finalizada com sucesso no sistema DOC ÂNCORA.\r\n\r\n` +
        `IMPORTANTE: O arquivo ZIP com todos os documentos foi baixado automaticamente. FAVOR ANEXAR O ARQUIVO '${folderName}.zip' A ESTE E-MAIL ANTES DE ENVIAR.\r\n\r\n` +
        `DADOS DO CLIENTE:\r\n` +
        `- Nome: ${client.name}\r\n` +
        `- CPF: ${client.cpf}\r\n` +
        `- Grupo: ${client.group}\r\n` +
        `- Cota: ${client.quota}\r\n` +
        `- Segmento: ${client.consortiumType}\r\n\r\n` +
        `Atenciosamente,\r\n` +
        `Equipe Doc Ancora`
      );

      const mailtoUrl = `mailto:${client.analystEmail}?subject=${subject}&body=${body}`;

      // Brief delay to ensure download starts before browser tries to open mailto
      setTimeout(() => {
        setIsFinalizing(false);
        window.location.href = mailtoUrl;
        alert(`Processo finalizado!\n\n1. O arquivo ZIP com os documentos foi baixado.\n2. O rascunho do Outlook será aberto.\n\nPOR FAVOR, ANEXE O ARQUIVO ZIP AO E-MAIL.`);
      }, 500);

    } catch (error) {
      console.error("Erro ao gerar pacote de documentos:", error);
      alert("Erro ao preparar os documentos para envio. Tente novamente.");
      setIsFinalizing(false);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, category: DocumentType) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(category);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);

      const newDoc: ClientDocument = {
        id: Math.random().toString(36).substr(2, 9),
        type: category,
        status: DocumentStatus.UPLOADED,
        fileName: file.name,
        fileData: reader.result as string,
        uploadDate: new Date().toISOString().split('T')[0],
        confidence: result.confidence
      };

      onAddDocument(newDoc);

      if (result.type !== category && result.type !== DocumentType.UNKNOWN) {
        alert(`Aviso: O documento enviado foi identificado como "${result.type}", mas foi adicionado em "${category}".`);
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn pb-20">
      {/* Profile Header */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative">
        <div className="flex items-center gap-5 w-full">
          <div className="w-16 h-16 bg-slate-50 rounded-2xl flex-shrink-0 flex items-center justify-center text-indigo-500 text-2xl border border-slate-200 shadow-inner relative">
            <i className="fa-solid fa-user-check"></i>
          </div>

          <div className="flex-grow">
            {!isEditing ? (
              <>
                <div className="flex items-center flex-wrap gap-3">
                  <h2 className="text-2xl font-bold text-slate-800">{client.name}</h2>
                  <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-full uppercase border border-indigo-100">
                    {client.consortiumType}
                  </span>
                  <div className="flex items-center gap-1.5 px-2 py-0.5 bg-amber-50 text-amber-700 text-[10px] font-bold rounded-full uppercase border border-amber-100">
                    <i className="fa-solid fa-star text-[8px]"></i>
                    Contemplação: {client.analystContemplation}
                  </div>
                  <button 
                    onClick={() => setIsEditing(true)}
                    className="ml-2 p-1 text-slate-300 hover:text-indigo-600 transition-colors"
                    title="Editar informações"
                  >
                    <i className="fa-solid fa-pen-to-square"></i>
                  </button>
                </div>

                <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-sm text-slate-500">
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-id-card text-xs text-slate-400"></i> {client.cpf}</span>
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-tags text-xs text-slate-400"></i> Grupo: <b className="text-slate-700">{client.group}</b> / Cota: <b className="text-slate-700">{client.quota}</b></span>
                  <span className="flex items-center gap-1.5"><i className="fa-solid fa-envelope text-xs text-slate-400"></i> Analista: <b className="text-slate-700">{client.analystEmail}</b></span>
                </div>

                <div className="mt-3 flex items-center gap-4">
                  <div className="flex items-center gap-2">
                    <img src={`https://ui-avatars.com/api/?name=${encodeURIComponent(client.analystName)}&background=6366f1&color=fff`} className="w-6 h-6 rounded-full" alt="Analyst" />
                    <span className="text-xs text-slate-500">Cadastro: <strong className="text-slate-800">{client.analystName}</strong></span>
                  </div>
                  <div className="flex items-center gap-2 border-l border-slate-100 pl-4">
                    <img src={`https://ui-avatars.com/api/?name=${encodeURIComponent(client.analystContemplation)}&background=f59e0b&color=fff`} className="w-6 h-6 rounded-full" alt="Contemplation Analyst" />
                    <span className="text-xs text-slate-500">Contemplação: <strong className="text-slate-800">{client.analystContemplation}</strong></span>
                  </div>
                </div>
              </>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3 w-full pr-12">
                <div className="col-span-1 md:col-span-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Nome Completo</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.name} onChange={(e) => setEditForm({...editForm, name: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">CPF</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.cpf} onChange={(e) => setEditForm({...editForm, cpf: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Email do Analista (Outlook)</label>
                  <input type="email" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.analystEmail} onChange={(e) => setEditForm({...editForm, analystEmail: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Tipo de Consórcio</label>
                  <select 
                    className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" 
                    value={editForm.consortiumType} 
                    onChange={(e) => setEditForm({...editForm, consortiumType: e.target.value})}
                  >
                    {consortiumOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Grupo</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.group} onChange={(e) => setEditForm({...editForm, group: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Cota</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.quota} onChange={(e) => setEditForm({...editForm, quota: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Analista Cadastro</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm" value={editForm.analystName} onChange={(e) => setEditForm({...editForm, analystName: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Analista Contemplação</label>
                  <input type="text" className="w-full px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-sm border-amber-200" value={editForm.analystContemplation} onChange={(e) => setEditForm({...editForm, analystContemplation: e.target.value})} />
                </div>
                <div className="flex items-end gap-2 col-span-full justify-between mt-4 pt-4 border-t border-slate-100">
                  <button 
                    onClick={handleDeleteConfirm}
                    className="bg-red-50 text-red-600 px-4 py-1.5 rounded text-sm font-bold hover:bg-red-100 transition-all flex items-center gap-2"
                  >
                    <i className="fa-solid fa-trash-can"></i>
                    Excluir Cadastro
                  </button>
                  <div className="flex items-center gap-2">
                    <button onClick={() => setIsEditing(false)} className="bg-slate-100 text-slate-500 px-4 py-1.5 rounded text-sm font-medium hover:bg-slate-200 transition-all">Cancelar</button>
                    <button onClick={handleSaveInfo} className="bg-indigo-600 text-white px-6 py-1.5 rounded text-sm font-bold shadow-md hover:bg-indigo-700 transition-all">Salvar Alterações</button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {!isEditing && (
          <div className="w-full md:w-auto flex flex-col items-end gap-1 bg-slate-50 p-4 rounded-xl border border-slate-100">
