                        </div>
                      </div>
                      {doc.confidence && (
                        <div className="flex items-center gap-1.5 text-[9px] text-indigo-500 font-bold bg-indigo-50/50 p-1 rounded">
                          <i className="fa-solid fa-robot"></i>
                          <span>IA: {(doc.confidence * 100).toFixed(0)}% de precisão</span>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <div className="border-2 border-dashed border-slate-100 rounded-xl py-8 text-center bg-slate-50/30">
                  <i className="fa-solid fa-file-arrow-up text-slate-200 text-3xl mb-2"></i>
                  <p className="text-xs text-slate-400">Obrigatório para conclusão da proposta</p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Action Bar */}
      <div className="fixed bottom-8 right-8 left-8 lg:left-1/3 xl:left-1/4 z-40">
        <div className="bg-slate-900 rounded-2xl text-white p-5 flex flex-col sm:flex-row items-center justify-between gap-4 shadow-2xl border border-slate-700 max-w-5xl mx-auto overflow-hidden">
          <div className="flex items-center gap-4">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${client.progress === 100 ? 'bg-emerald-500' : 'bg-slate-800 text-slate-500'}`}>
              <i className={`fa-solid ${client.progress === 100 ? 'fa-check' : 'fa-clock'}`}></i>
            </div>
            <div>
              <p className="font-bold text-sm">Status da Proposta</p>
              <p className="text-xs text-slate-400">{client.progress === 100 ? 'Documentação completa' : 'Pendente de documentos obrigatórios'}</p>
            </div>
          </div>

          <button 
            disabled={client.progress < 100 || isFinalizing} 
            onClick={handleFinalizeProcess}
            className={`px-8 py-3 rounded-xl font-bold transition-all shadow-lg flex items-center gap-3 relative overflow-hidden ${
              client.progress === 100 
                ? 'bg-indigo-600 hover:bg-indigo-700 active:scale-95' 
                : 'bg-slate-800 text-slate-600 cursor-not-allowed'
            }`}
          >
            {isFinalizing ? (
              <>
                <i className="fa-solid fa-circle-notch animate-spin"></i>
                <span>Compactando e Enviando...</span>
              </>
            ) : (
              <>
                <i className="fa-solid fa-paper-plane"></i>
                <span>Finalizar e Anexar Arquivos</span>
              </>
            )}
            {client.progress === 100 && !isFinalizing && (
              <span className="absolute inset-0 bg-white/20 animate-pulse pointer-events-none"></span>
            )}
          </button>
        </div>
      </div>

      {/* Document Viewer Modal */}
      {viewingDoc && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center">
                  <i className="fa-solid fa-file-invoice"></i>
                </div>
                <div>
                  <h3 className="font-bold text-slate-800">{viewingDoc.type}</h3>
                  <p className="text-xs text-slate-400">{viewingDoc.fileName}</p>
                </div>
              </div>
              <button onClick={() => setViewingDoc(null)} className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-slate-600 transition-colors">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <div className="flex-grow bg-slate-100 p-8 flex items-center justify-center overflow-auto">
              {viewingDoc.fileData ? (
                <img src={viewingDoc.fileData} alt="Documento" className="max-w-full rounded-lg shadow-lg border border-white" />
              ) : (
                <div className="text-center text-slate-400">
                  <i className="fa-solid fa-eye-slash text-5xl mb-4 opacity-20"></i>
                  <p>Visualização indisponível para este arquivo mock.</p>
                </div>
              )}
            </div>
            <div className="p-6 border-t border-slate-100 flex justify-end gap-3">
               <button onClick={() => setViewingDoc(null)} className="px-6 py-2.5 bg-slate-100 text-slate-600 font-bold rounded-xl text-sm">Fechar</button>
               <button className="px-6 py-2.5 bg-indigo-600 text-white font-bold rounded-xl text-sm flex items-center gap-2">
                 <i className="fa-solid fa-download"></i> Baixar Arquivo
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

