import React, { useState, useEffect } from 'react';
import { Client, DocumentStatus, DocumentType, ClientDocument } from '../types';
import { classifyDocument } from '../services/geminiService';
import JSZip from 'jszip';

interface ClientDetailsProps {
  client: Client;
  onAddDocument: (newDoc: ClientDocument) => void;
  onRemoveDocument: (docId: string) => void;
  onUpdateClientInfo: (updates: Partial<Client>) => void;
  onDeleteClient: () => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, onAddDocument, onRemoveDocument, onUpdateClientInfo, onDeleteClient }) => {
  const [isProcessing, setIsProcessing] = useState<DocumentType | null>(null);
  const [isFinalizing, setIsFinalizing] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [viewingDoc, setViewingDoc] = useState<ClientDocument | null>(null);
  const [editForm, setEditForm] = useState({
    name: '',
    cpf: '',
    group: '',
    quota: '',
    consortiumType: '',
    analystName: '',
    analystEmail: '',
    analystContemplation: ''
  });

  const categories = [
    DocumentType.ID,
    DocumentType.RESIDENCE,
    DocumentType.INCOME,
    DocumentType.CONTRACT
  ];

  const consortiumOptions = ['Imobiliário', 'Automotivo', 'Pesados', 'Serviços', 'Motos', 'Consórcio de Ouro', 'Outros Bens'];

  useEffect(() => {
    setEditForm({
      name: client.name,
      cpf: client.cpf,
      group: client.group,
      quota: client.quota,
      consortiumType: client.consortiumType,
      analystName: client.analystName,
      analystEmail: client.analystEmail || `${client.analystName.toLowerCase().replace(/\s+/g, '.')}@consorcioancora.com.br`,
      analystContemplation: client.analystContemplation
    });
  }, [client, isEditing]);

  const handleSaveInfo = () => {
    onUpdateClientInfo(editForm);
    setIsEditing(false);
  };

  const handleDeleteConfirm = () => {
    if (window.confirm(`Tem certeza que deseja excluir permanentemente o cadastro de ${client.name}? Esta ação não pode ser desfeita.`)) {
      onDeleteClient();
    }
  };

  const handleFinalizeProcess = async () => {
    if (client.progress < 100) return;

    setIsFinalizing(true);

    try {
      // 1. Create a ZIP file of all documents
      const zip = new JSZip();
      const safeName = client.name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, '_');
      const folderName = `Documentos_${safeName}`;
      const folder = zip.folder(folderName);

      if (folder) {
        client.documents.forEach((doc) => {
          if (doc.fileData) {
            const base64Content = doc.fileData.split(',')[1];
            folder.file(`${doc.type.replace(/[^a-zA-Z0-9]/g, '_')}_${doc.fileName}`, base64Content, { base64: true });
          }
        });
      }

      // 2. Generate and trigger download
      const content = await zip.generateAsync({ type: 'blob' });
      const downloadLink = document.createElement('a');
      downloadLink.href = URL.createObjectURL(content);
      downloadLink.download = `${folderName}.zip`;
      document.body.appendChild(downloadLink);
      downloadLink.click();
      document.body.removeChild(downloadLink);

      // 3. Prepare Email Content for Outlook
      const subject = encodeURIComponent(`[DOC ÂNCORA] Documentação Completa - ${client.name} (G: ${client.group} / C: ${client.quota})`);

      const body = encodeURIComponent(
        `Prezado(a) ${client.analystName},\r\n\r\n` +
        `A documentação do cliente ${client.name} foi finalizada e validada no sistema DOC ÂNCORA.\r\n\r\n` +
        `>>> AÇÃO NECESSÁRIA: O arquivo ZIP com todos os documentos foi baixado automaticamente. FAVOR ANEXAR O ARQUIVO '${folderName}.zip' A ESTE E-MAIL ANTES DE ENVIAR.\r\n\r\n` +
        `DADOS DO CLIENTE:\r\n` +
        `- Nome: ${client.name}\r\n` +
        `- CPF: ${client.cpf}\r\n` +
        `- Grupo/Cota: ${client.group} / ${client.quota}\r\n` +
        `- Segmento: ${client.consortiumType}\r\n\r\n` +
        `Atenciosamente,\r\n` +
        `Plataforma Doc Âncora`
      );

      const mailtoUrl = `mailto:${client.analystEmail}?subject=${subject}&body=${body}`;

      setTimeout(() => {
        setIsFinalizing(false);
        window.location.href = mailtoUrl;
        alert(`Processo Finalizado!\n\n1. O arquivo ZIP foi baixado.\n2. O Outlook será aberto.\n\nIMPORTANTE: Anexe o ZIP baixado manualmente ao e-mail.`);
      }, 1000);

    } catch (error) {
      console.error("Erro ao gerar pacote de documentos:", error);
      alert("Erro ao preparar os documentos para envio. Tente novamente.");
      setIsFinalizing(false);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, category: DocumentType) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(category);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);

      const newDoc: ClientDocument = {
        id: Math.random().toString(36).substr(2, 9),
        type: category,
        status: DocumentStatus.UPLOADED,
        fileName: file.name,
        fileData: reader.result as string,
        uploadDate: new Date().toISOString().split('T')[0],
        confidence: result.confidence
      };

      onAddDocument(newDoc);

      if (result.type !== category && result.type !== DocumentType.UNKNOWN) {
        alert(`Aviso de IA: O documento parece ser um "${result.type}", mas você está salvando em "${category}". Verifique se está correto.`);
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn pb-24">
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative">
        <div className="flex items-center gap-6 w-full">
          <div className="w-20 h-20 bg-gradient-to-br from-indigo-500 to-blue-600 rounded-3xl flex-shrink-0 flex items-center justify-center text-white text-3xl shadow-xl border-4 border-white">
            <i className="fa-solid fa-user-check"></i>
          </div>

          <div className="flex-grow">
            {!isEditing ? (
              <>
                <div className="flex items-center flex-wrap gap-3">
                  <h2 className="text-3xl font-black text-slate-800 tracking-tight">{client.name}</h2>
                  <span className="px-3 py-1 bg-indigo-50 text-indigo-600 text-xs font-black rounded-full uppercase border border-indigo-100">
                    {client.consortiumType}
                  </span>
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-amber-50 text-amber-700 text-xs font-black rounded-full uppercase border border-amber-100">
                    <i className="fa-solid fa-star"></i>
                    Contemplação: {client.analystContemplation}
                  </div>
                  <button 
                    onClick={() => setIsEditing(true)}
                    className="ml-2 p-2 text-slate-300 hover:text-indigo-600 hover:bg-slate-50 rounded-full transition-all"
                    title="Editar informações"
                  >
                    <i className="fa-solid fa-pen-to-square text-lg"></i>
                  </button>
                </div>

                <div className="flex flex-wrap gap-x-6 gap-y-2 mt-2 text-sm text-slate-500 font-medium">
                  <span className="flex items-center gap-2"><i className="fa-solid fa-id-card text-slate-400"></i> {client.cpf}</span>
                  <span className="flex items-center gap-2"><i className="fa-solid fa-tags text-slate-400"></i> Grupo/Cota: <b className="text-slate-700">{client.group} / {client.quota}</b></span>
                  <span className="flex items-center gap-2"><i className="fa-solid fa-envelope text-slate-400"></i> Analista: <b className="text-slate-700">{client.analystEmail}</b></span>
                </div>
              </>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 w-full pr-12 animate-slideUp">
                <div className="col-span-1 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome Completo</label>
                  <input type="text" className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={editForm.name} onChange={(e) => setEditForm({...editForm, name: e.target.value})} />
                </div>
                <div>
