            </div>
            <div>
              <p className="font-black text-lg tracking-tight">{client.progress === 100 ? 'STATUS: DOCUMENTAÇÃO COMPLETA' : 'STATUS: PENDENTE'}</p>
              <p className="text-xs text-gray-400 font-bold tracking-widest uppercase">{client.progress === 100 ? 'Pronto para envio ao analista' : 'Aguardando arquivos obrigatórios'}</p>
            </div>
          </div>

          <button 
            disabled={client.progress < 100 || isFinalizing} 
            onClick={handleFinalizeProcess}
            className={`px-10 py-4 rounded-2xl font-black text-sm tracking-widest uppercase transition-all shadow-xl flex items-center gap-3 relative overflow-hidden group ${
