import ClientDetails from './components/ClientDetails';
import Header from './components/Header';
import Reports from './components/Reports';
import Segments from './components/Segments';
import AddClientModal from './components/AddClientModal';
import AnalystManagement from './components/AnalystManagement';

const DEFAULT_REQUIRED = [DocumentType.ID, DocumentType.RESIDENCE, DocumentType.INCOME, DocumentType.CONTRACT];

const MOCK_ANALYSTS: Analyst[] = [
  { id: '1', name: 'Ricardo Alencar', email: 'ricardo.alencar@consorcioancora.com.br', role: 'Ambos' },
  { id: '2', name: 'Beatriz Costa', email: 'beatriz.costa@consorcioancora.com.br', role: 'Cadastro' },
  { id: '3', name: 'Mariana Luz', email: 'mariana.luz@consorcioancora.com.br', role: 'Contemplação' },
  { id: '4', name: 'Fernando Silva', email: 'fernando.silva@consorcioancora.com.br', role: 'Contemplação' }
];

const MOCK_CLIENTS: Client[] = [
  {
    id: '1',
    name: 'João Silva Oliveira',
    cpf: '123.456.789-00',
    clientType: 'PF',
    consortiumType: 'Imobiliário',
    group: 'A120',
    quota: '045',
    analystName: 'Ricardo Alencar',
    analystEmail: 'ricardo.alencar@consorcioancora.com.br',
    analystContemplation: 'Mariana Luz',
    progress: 25,
    documents: [
      { id: 'd1', type: DocumentType.ID, status: DocumentStatus.UPLOADED, fileName: 'cnh_joao.jpg', uploadDate: '2023-10-15' },
    ],
    requiredDocumentTypes: DEFAULT_REQUIRED
  }
];

export type ViewType = 'dashboard' | 'reports' | 'segments' | 'analysts';

const App: React.FC = () => {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [analysts, setAnalysts] = useState<Analyst[]>(MOCK_ANALYSTS);
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  const selectedClient = clients.find(c => c.id === selectedClientId);

  const calculateProgress = (docs: ClientDocument[], requiredTypes: DocumentType[]) => {
    if (requiredTypes.length === 0) return 100;
    const completedTypes = requiredTypes.filter(type => 
      docs.some(doc => doc.type === type && doc.status === DocumentStatus.UPLOADED)
    );
    return Math.round((completedTypes.length / requiredTypes.length) * 100);
  };

  const handleAddClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    setSelectedClientId(newClient.id);
    setIsAddModalOpen(false);
  };

  const handleAddAnalyst = (analyst: Analyst) => {
    setAnalysts(prev => [...prev, analyst]);
  };

  const handleRemoveAnalyst = (id: string) => {
    setAnalysts(prev => prev.filter(a => a.id !== id));
  };

  const handleAddDocument = (clientId: string, newDoc: ClientDocument) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = [...client.documents, newDoc];
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs, client.requiredDocumentTypes) 
      };
    }));
  };

  const handleRemoveDocument = (clientId: string, docId: string) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = client.documents.filter(d => d.id !== docId);
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs, client.requiredDocumentTypes) 
      };
    }));
  };

  const handleUpdateClientInfo = (clientId: string, updates: Partial<Client>) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedClient = { ...client, ...updates };
      if (updates.requiredDocumentTypes || updates.documents) {
        updatedClient.progress = calculateProgress(updatedClient.documents, updatedClient.requiredDocumentTypes);
      }
      return updatedClient;
    }));
  };

  const handleToggleRequirement = (clientId: string, docType: DocumentType) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const isCurrentlyRequired = client.requiredDocumentTypes.includes(docType);
      const newRequired = isCurrentlyRequired 
        ? client.requiredDocumentTypes.filter(t => t !== docType)
        : [...client.requiredDocumentTypes, docType];

      return {
        ...client,
        requiredDocumentTypes: newRequired,
        progress: calculateProgress(client.documents, newRequired)
      };
    }));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(client => client.id !== clientId));
    setSelectedClientId(null);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.cpf.includes(searchTerm) ||
    c.group.includes(searchTerm) ||
    c.quota.includes(searchTerm)
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <Header activeView={activeView} onViewChange={setActiveView} />

      <main className="flex-grow container mx-auto px-4 py-8">
        {activeView === 'dashboard' && (
          <div className="flex flex-col lg:flex-row gap-8 animate-fadeIn">
            <div className="w-full lg:w-1/3 xl:w-1/4">
              <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="p-4 border-b border-gray-100 space-y-3">
                  <div className="relative">
                    <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
                    <input 
                      type="text" 
                      placeholder="Buscar cliente ou cota..."
                      className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <button 
                    onClick={() => setIsAddModalOpen(true)}
                    className="w-full py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-sm font-bold transition-all flex items-center justify-center gap-2 shadow-sm"
                  >
                    <i className="fa-solid fa-plus"></i>
                    Novo Cadastro
                  </button>
                </div>
                <ClientList 
                  clients={filteredClients} 
                  selectedId={selectedClientId} 
                  onSelect={setSelectedClientId} 
                />
              </div>
            </div>

            <div className="w-full lg:w-2/3 xl:w-3/4">
              {selectedClient ? (
                <ClientDetails 
                  client={selectedClient} 
                  onAddDocument={(newDoc) => handleAddDocument(selectedClient.id, newDoc)}
                  onRemoveDocument={(docId) => handleRemoveDocument(selectedClient.id, docId)}
                  onUpdateClientInfo={(updates) => handleUpdateClientInfo(selectedClient.id, updates)}
                  onDeleteClient={() => handleDeleteClient(selectedClient.id)}
                  onToggleRequirement={(docType) => handleToggleRequirement(selectedClient.id, docType)}
                />
              ) : (
                <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-12 flex flex-col items-center justify-center text-center">
                  <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center text-blue-600 mb-6">
                    <i className="fa-solid fa-users text-3xl"></i>
                  </div>
                  <h2 className="text-xl font-semibold text-gray-800 mb-2">Selecione um Cliente</h2>
                  <p className="text-gray-500 max-w-xs mx-auto">
                    Escolha um cliente da lista ao lado para gerenciar documentos e acompanhar o status.
                  </p>
                </div>
              )}
            </div>
          </div>
        )}

        {activeView === 'reports' && <Reports clients={clients} />}
        {activeView === 'segments' && <Segments clients={clients} onSelectClient={(id) => { setSelectedClientId(id); setActiveView('dashboard'); }} />}
        {activeView === 'analysts' && <AnalystManagement analysts={analysts} onAdd={handleAddAnalyst} onRemove={handleRemoveAnalyst} />}
      </main>

      {isAddModalOpen && (
        <AddClientModal 
          onClose={() => setIsAddModalOpen(false)} 
          onAdd={handleAddClient} 
          analysts={analysts}
        />
      )}

      <footer className="bg-white border-t border-gray-200 py-6 text-center text-gray-400 text-sm">
        <p>&copy; 2024 Triagem Ancorada - Tecnologia para Gestão Documental</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Client, DocumentStatus, DocumentType, ClientDocument } from '../types';
import { classifyDocument } from '../services/geminiService';
import JSZip from 'jszip';

interface ClientDetailsProps {
  client: Client;
  onAddDocument: (newDoc: ClientDocument) => void;
  onRemoveDocument: (docId: string) => void;
  onUpdateClientInfo: (updates: Partial<Client>) => void;
  onDeleteClient: () => void;
  onToggleRequirement: (docType: DocumentType) => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ 
  client, 
  onAddDocument, 
  onRemoveDocument, 
  onUpdateClientInfo, 
  onDeleteClient,
  onToggleRequirement
}) => {
  const [isProcessing, setIsProcessing] = useState<DocumentType | null>(null);
  const [isFinalizing, setIsFinalizing] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [viewingDoc, setViewingDoc] = useState<ClientDocument | null>(null);
  const [editForm, setEditForm] = useState({
    name: '',
    cpf: '',
    group: '',
    quota: '',
    consortiumType: '',
    analystName: '',
    analystEmail: '',
    analystContemplation: ''
  });

  const categories = [
    DocumentType.ID,
    DocumentType.RESIDENCE,
    DocumentType.INCOME,
    DocumentType.CONTRACT
  ];

  const consortiumOptions = ['Imobiliário', 'Automotivo', 'Pesados', 'Serviços', 'Motos', 'Consórcio de Ouro', 'Outros Bens'];

  useEffect(() => {
    setEditForm({
      name: client.name,
      cpf: client.cpf,
      group: client.group,
      quota: client.quota,
      consortiumType: client.consortiumType,
      analystName: client.analystName,
      analystEmail: client.analystEmail || `${client.analystName.toLowerCase().replace(/\s+/g, '.')}@consorcioancora.com.br`,
      analystContemplation: client.analystContemplation
    });
  }, [client, isEditing]);

  const handleSaveInfo = () => {
    onUpdateClientInfo(editForm);
    setIsEditing(false);
  };

  const handleDeleteConfirm = () => {
    if (window.confirm(`Tem certeza que deseja excluir permanentemente o cadastro de ${client.name}? Esta ação não pode ser desfeita.`)) {
      onDeleteClient();
    }
  };

  const handleFinalizeProcess = async () => {
    if (client.progress < 100) return;

    setIsFinalizing(true);

    try {
      const zip = new JSZip();
      const safeName = client.name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, '_');
      const folderName = `Documentos_${safeName}`;
      const folder = zip.folder(folderName);

      if (folder) {
        client.documents.forEach((doc) => {
          if (doc.fileData) {
            const base64Content = doc.fileData.split(',')[1];
            folder.file(`${doc.type.replace(/[^a-zA-Z0-9]/g, '_')}_${doc.fileName}`, base64Content, { base64: true });
          }
        });
      }

      const content = await zip.generateAsync({ type: 'blob' });
      const downloadLink = document.createElement('a');
      downloadLink.href = URL.createObjectURL(content);
      downloadLink.download = `${folderName}.zip`;
      document.body.appendChild(downloadLink);
      downloadLink.click();
      document.body.removeChild(downloadLink);

      const subject = encodeURIComponent(`[TRIAGEM ANCORADA] Documentação Completa - ${client.name} (G: ${client.group} / C: ${client.quota})`);
      const body = encodeURIComponent(
        `Prezado(a) ${client.analystName},\r\n\r\n` +
        `A documentação do cliente ${client.name} foi finalizada e validada no sistema TRIAGEM ANCORADA.\r\n\r\n` +
        `>>> AÇÃO NECESSÁRIA: O arquivo ZIP com todos os documentos foi baixado automaticamente. FAVOR ANEXAR O ARQUIVO '${folderName}.zip' A ESTE E-MAIL ANTES DE ENVIAR.\r\n\r\n` +
        `DADOS DO CLIENTE:\r\n` +
        `- Nome: ${client.name}\r\n` +
        `- Documento: ${client.cpf}\r\n` +
        `- Grupo/Cota: ${client.group} / ${client.quota}\r\n` +
        `- Segmento: ${client.consortiumType}\r\n\r\n` +
        `Atenciosamente,\r\n` +
        `Plataforma Triagem Ancorada`
      );

      const mailtoUrl = `mailto:${client.analystEmail}?subject=${subject}&body=${body}`;

      setTimeout(() => {
        setIsFinalizing(false);
        window.location.href = mailtoUrl;
        alert(`Processo Finalizado!\n\n1. O arquivo ZIP foi baixado.\n2. O Outlook será aberto.\n\nIMPORTANTE: Anexe o ZIP baixado manualmente ao e-mail.`);
      }, 1000);

    } catch (error) {
      console.error("Erro ao gerar pacote de documentos:", error);
      alert("Erro ao preparar os documentos para envio. Tente novamente.");
      setIsFinalizing(false);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, category: DocumentType) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(category);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);

      const newDoc: ClientDocument = {
        id: Math.random().toString(36).substr(2, 9),
        type: category,
        status: DocumentStatus.UPLOADED,
        fileName: file.name,
        fileData: reader.result as string,
        uploadDate: new Date().toISOString().split('T')[0],
        confidence: result.confidence
      };

      onAddDocument(newDoc);

      if (result.type !== category && result.type !== DocumentType.UNKNOWN) {
        alert(`Aviso de IA: O documento parece ser um "${result.type}", mas você está salvando em "${category}". Verifique se está correto.`);
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn pb-24">
      <div className="bg-white rounded-3xl shadow-sm border border-gray-200 p-8 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative">
        <div className="flex items-center gap-6 w-full">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-500 to-gray-600 rounded-3xl flex-shrink-0 flex items-center justify-center text-white text-3xl shadow-xl border-4 border-white">
            <i className={`fa-solid ${client.clientType === 'PF' ? 'fa-user' : 'fa-building-shield'}`}></i>
          </div>

          <div className="flex-grow">
            {!isEditing ? (
              <>
                <div className="flex items-center flex-wrap gap-3">
                  <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest border ${
                    client.clientType === 'PF' ? 'bg-blue-50 text-blue-600 border-blue-100' : 'bg-gray-100 text-gray-500 border-gray-200'
                  }`}>
                    {client.clientType === 'PF' ? 'Pessoa Física' : 'Pessoa Jurídica'}
                  </span>
                  <h2 className="text-3xl font-black text-gray-800 tracking-tight">{client.name}</h2>
                  <span className="px-3 py-1 bg-blue-50 text-blue-600 text-xs font-black rounded-full uppercase border border-blue-100">
                    {client.consortiumType}
                  </span>
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-amber-50 text-amber-700 text-xs font-black rounded-full uppercase border border-amber-100">
                    <i className="fa-solid fa-star"></i>
                    Contemplação: {client.analystContemplation}
                  </div>
                  <button 
                    onClick={() => setIsEditing(true)}
                    className="ml-2 p-2 text-gray-300 hover:text-blue-600 hover:bg-gray-50 rounded-full transition-all"
                    title="Editar informações"
                  >
                    <i className="fa-solid fa-pen-to-square text-lg"></i>
                  </button>
                </div>

                <div className="flex flex-wrap gap-x-6 gap-y-2 mt-2 text-sm text-gray-500 font-medium">
                  <span className="flex items-center gap-2"><i className="fa-solid fa-id-card text-gray-400"></i> {client.clientType === 'PF' ? 'CPF' : 'CNPJ'}: {client.cpf}</span>
                  <span className="flex items-center gap-2"><i className="fa-solid fa-tags text-gray-400"></i> Grupo/Cota: <b className="text-gray-700">{client.group} / {client.quota}</b></span>
                  <span className="flex items-center gap-2"><i className="fa-solid fa-envelope text-gray-400"></i> Analista: <b className="text-gray-700">{client.analystEmail}</b></span>
                </div>
              </>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 w-full pr-12 animate-slideUp">
                <div className="col-span-1 md:col-span-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{client.clientType === 'PF' ? 'Nome Completo' : 'Razão Social'}</label>
                  <input type="text" className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold" value={editForm.name} onChange={(e) => setEditForm({...editForm, name: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{client.clientType === 'PF' ? 'CPF' : 'CNPJ'}</label>
                  <input type="text" className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold" value={editForm.cpf} onChange={(e) => setEditForm({...editForm, cpf: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Email do Analista</label>
                  <input type="email" className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold" value={editForm.analystEmail} onChange={(e) => setEditForm({...editForm, analystEmail: e.target.value})} />
                </div>
                <div className="flex items-end gap-2 col-span-full justify-between mt-6 pt-6 border-t border-gray-100">
                  <button 
                    onClick={handleDeleteConfirm}
                    className="bg-red-50 text-red-600 px-6 py-2.5 rounded-xl text-sm font-black hover:bg-red-100 transition-all flex items-center gap-2"
                  >
                    <i className="fa-solid fa-trash-can"></i>
                    EXCLUIR CADASTRO
                  </button>
                  <div className="flex items-center gap-3">
                    <button onClick={() => setIsEditing(false)} className="bg-gray-100 text-gray-500 px-6 py-2.5 rounded-xl text-sm font-bold hover:bg-gray-200 transition-all">Cancelar</button>
                    <button onClick={handleSaveInfo} className="bg-blue-600 text-white px-8 py-2.5 rounded-xl text-sm font-black shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all">SALVAR DADOS</button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {!isEditing && (
          <div className="w-full md:w-auto flex flex-col items-end gap-2 bg-gray-50 p-6 rounded-2xl border border-gray-100">
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Documentação</span>
            <div className="w-full md:w-56 h-3 bg-gray-200 rounded-full overflow-hidden shadow-inner">
              <div 
                className={`h-full transition-all duration-1000 ${client.progress === 100 ? 'bg-emerald-500' : 'bg-blue-600'}`} 
                style={{ width: `${client.progress}%` }}
              ></div>
            </div>
            <span className={`text-lg font-black ${client.progress === 100 ? 'text-emerald-600' : 'text-blue-600'}`}>{client.progress}% <span className="text-xs uppercase ml-1">concluído</span></span>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 gap-6">
        {categories.map((category) => {
          const categoryDocs = client.documents.filter(d => d.type === category);
          const isComplete = categoryDocs.length > 0;
          const isRequired = client.requiredDocumentTypes.includes(category);

          return (
            <div key={category} className={`bg-white rounded-3xl border-2 p-8 transition-all duration-300 shadow-sm ${!isRequired ? 'border-gray-50 opacity-80' : isComplete ? 'border-emerald-100' : 'border-gray-100 hover:border-gray-200'}`}>
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-8">
                <div className="flex items-center gap-5">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-lg transition-transform hover:scale-105 ${!isRequired ? 'bg-gray-200 text-gray-400' : isComplete ? 'bg-emerald-500 text-white' : 'bg-gray-100 text-gray-400'}`}>
                    <i className={`fa-solid ${
                      category === DocumentType.ID ? 'fa-address-card' :
                      category === DocumentType.RESIDENCE ? 'fa-house' :
                      category === DocumentType.INCOME ? 'fa-receipt' : 'fa-file-signature'
                    }`}></i>
                  </div>
                  <div>
                    <div className="flex items-center gap-3">
                      <h3 className="text-xl font-black text-gray-800 tracking-tight">{category}</h3>
                      {!isRequired && (
                        <span className="px-2 py-0.5 bg-gray-100 text-gray-500 text-[10px] font-black rounded-lg uppercase tracking-widest border border-gray-200">OPCIONAL</span>
                      )}
                    </div>
                    <p className="text-sm text-gray-400 font-bold uppercase tracking-wider">
                      {isComplete ? `${categoryDocs.length} ARQUIVO(S) ENVIADO(S)` : isRequired ? 'PENDENTE DE ENVIO' : 'REQUISITO DESATIVADO'}
                    </p>
                  </div>
                </div>

                <div className="flex items-center gap-4">
                  <button 
                    onClick={() => onToggleRequirement(category)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border ${
                      isRequired 
                        ? 'bg-blue-50 text-blue-600 border-blue-200 hover:bg-blue-100' 
                        : 'bg-gray-50 text-gray-400 border-gray-200 hover:bg-gray-100'
                    }`}
                  >
                    <i className={`fa-solid ${isRequired ? 'fa-toggle-on' : 'fa-toggle-off'} text-lg`}></i>
                    {isRequired ? 'Obrigatório' : 'Caso Especial'}
                  </button>

                  <label className="flex items-center justify-center gap-3 bg-blue-600 text-white hover:bg-blue-700 px-6 py-3.5 rounded-2xl text-sm font-black cursor-pointer transition-all shadow-lg shadow-blue-100 active:scale-95 group">
                    {isProcessing === category ? (
                      <i className="fa-solid fa-circle-notch animate-spin"></i>
                    ) : (
                      <i className="fa-solid fa-arrow-up-from-bracket group-hover:-translate-y-1 transition-transform"></i>
                    )}
                    <span>{isComplete ? 'Substituir' : 'Enviar'}</span>
                    <input type="file" className="hidden" accept="image/*,application/pdf" onChange={(e) => handleFileUpload(e, category)} disabled={isProcessing !== null} />
                  </label>
                </div>
              </div>

              {categoryDocs.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {categoryDocs.map((doc) => (
                    <div key={doc.id} className="group bg-gray-50 border border-gray-100 rounded-2xl p-4 flex flex-col gap-3 hover:border-blue-300 hover:bg-white transition-all shadow-sm">
                      <div className="flex items-start justify-between">
                        <div className="flex items-center gap-3 overflow-hidden">
                          <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-red-500 border border-gray-100">
                             <i className="fa-solid fa-file-pdf"></i>
                          </div>
                          <div className="overflow-hidden">
                            <p className="text-sm font-black text-gray-700 truncate">{doc.fileName}</p>
                            <p className="text-[10px] text-gray-400 font-bold tracking-widest">{doc.uploadDate}</p>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button onClick={() => setViewingDoc(doc)} className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"><i className="fa-solid fa-eye"></i></button>
                          <button onClick={() => onRemoveDocument(doc.id)} className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"><i className="fa-solid fa-trash-can"></i></button>
                        </div>
                      </div>
                      {doc.confidence && (
                        <div className="flex items-center gap-2 text-[10px] text-blue-600 font-black bg-blue-50/70 py-1.5 px-3 rounded-xl border border-blue-100">
                          <i className="fa-solid fa-brain"></i>
                          <span>IA VALIDOU COM {(doc.confidence * 100).toFixed(0)}% DE PRECISÃO</span>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <div className="border-2 border-dashed border-gray-100 rounded-3xl py-12 text-center bg-gray-50/50">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-gray-200 mx-auto mb-4 shadow-sm border border-gray-50">
                    <i className={`fa-solid ${isRequired ? 'fa-file-shield' : 'fa-circle-info'} text-3xl`}></i>
                  </div>
                  <p className="text-sm text-gray-400 font-bold uppercase tracking-widest">
                    {isRequired ? 'Documento Obrigatório' : 'Documento Opcional'}
                  </p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="fixed bottom-10 right-10 left-10 lg:left-1/3 xl:left-1/4 z-40">
        <div className="bg-gray-900 rounded-3xl text-white p-6 flex flex-col sm:flex-row items-center justify-between gap-6 shadow-2xl border border-gray-800 max-w-5xl mx-auto overflow-hidden animate-slideUp">
          <div className="flex items-center gap-5">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl ${client.progress === 100 ? 'bg-emerald-500 shadow-emerald-500/20 shadow-lg' : 'bg-gray-800 text-gray-600'}`}>
              <i className={`fa-solid ${client.progress === 100 ? 'fa-check-double' : 'fa-hourglass-half'}`}></i>
            </div>
            <div>
              <p className="font-black text-lg tracking-tight">{client.progress === 100 ? 'STATUS: DOCUMENTAÇÃO COMPLETA' : 'STATUS: PENDENTE'}</p>
              <p className="text-xs text-gray-400 font-bold tracking-widest uppercase">{client.progress === 100 ? 'Pronto para envio ao analista' : 'Aguardando arquivos obrigatórios'}</p>
            </div>
          </div>

          <button 
            disabled={client.progress < 100 || isFinalizing} 
            onClick={handleFinalizeProcess}
            className={`px-10 py-4 rounded-2xl font-black text-sm tracking-widest uppercase transition-all shadow-xl flex items-center gap-3 relative overflow-hidden group ${
              client.progress === 100 
                ? 'bg-gradient-to-r from-blue-600 to-gray-600 hover:from-blue-500 hover:to-gray-500 active:scale-95' 
                : 'bg-gray-800 text-gray-600 cursor-not-allowed'
            }`}
          >
            {isFinalizing ? (
              <>
                <i className="fa-solid fa-circle-notch animate-spin"></i>
                <span>Gerando Pacote...</span>
              </>
            ) : (
              <>
                <i className="fa-solid fa-paper-plane group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform"></i>
                <span>FINALIZAR E ENVIAR</span>
              </>
            )}
            {client.progress === 100 && !isFinalizing && (
              <span className="absolute inset-0 bg-white/10 animate-pulse pointer-events-none"></span>
            )}
          </button>
        </div>
      </div>

      {viewingDoc && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-gray-900/90 backdrop-blur-md animate-fadeIn">
          <div className="bg-white rounded-[40px] w-full max-w-5xl max-h-[90vh] flex flex-col shadow-2xl overflow-hidden animate-slideUp">
            <div className="p-8 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
              <div className="flex items-center gap-5">
                <div className="w-14 h-14 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-lg">
                  <i className="fa-solid fa-file-contract text-2xl"></i>
                </div>
                <div>
                  <h3 className="text-xl font-black text-gray-800 tracking-tight">{viewingDoc.type}</h3>
                  <p className="text-xs text-gray-400 font-bold tracking-widest uppercase">{viewingDoc.fileName}</p>
                </div>
              </div>
              <button onClick={() => setViewingDoc(null)} className="w-12 h-12 flex items-center justify-center text-gray-300 hover:text-gray-600 transition-colors rounded-full hover:bg-white shadow-sm border border-gray-100">
                <i className="fa-solid fa-xmark text-2xl"></i>
              </button>
            </div>
            <div className="flex-grow bg-gray-200 p-12 flex items-center justify-center overflow-auto custom-scrollbar">
              {viewingDoc.fileData ? (
                <div className="relative group">
                   <img src={viewingDoc.fileData} alt="Documento" className="max-w-full rounded-2xl shadow-2xl border-4 border-white" />
                   <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity rounded-2xl"></div>
                </div>
              ) : (
                <div className="text-center text-gray-400">
                  <i className="fa-solid fa-eye-slash text-6xl mb-6 opacity-20"></i>
                  <p className="font-bold">Prévia indisponível para este arquivo.</p>
                </div>
              )}
            </div>
            <div className="p-8 border-t border-gray-100 flex justify-end gap-4 bg-white">
               <button onClick={() => setViewingDoc(null)} className="px-8 py-3 bg-gray-100 text-gray-600 font-black rounded-2xl text-xs tracking-widest uppercase hover:bg-gray-200 transition-all">Fechar</button>
               <button className="px-10 py-3 bg-blue-600 text-white font-black rounded-2xl text-xs tracking-widest uppercase shadow-lg shadow-blue-100 flex items-center gap-3 hover:bg-blue-700 transition-all active:scale-95">
                 <i className="fa-solid fa-download"></i> Baixar Original
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ClientDetails;

import React, { useState, useEffect } from 'react';
import { Client, DocumentStatus, DocumentType, ClientDocument } from '../types';
import { classifyDocument } from '../services/geminiService';
import JSZip from 'jszip';

interface ClientDetailsProps {
  client: Client;
  onAddDocument: (newDoc: ClientDocument) => void;
  onRemoveDocument: (docId: string) => void;
  onUpdateClientInfo: (updates: Partial<Client>) => void;
  onDeleteClient: () => void;
  onToggleRequirement: (docType: DocumentType) => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ 
  client, 
  onAddDocument, 
  onRemoveDocument, 
  onUpdateClientInfo, 
  onDeleteClient,
  onToggleRequirement
}) => {
  const [isProcessing, setIsProcessing] = useState<DocumentType | null>(null);
  const [isFinalizing, setIsFinalizing] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [viewingDoc, setViewingDoc] = useState<ClientDocument | null>(null);
  const [editForm, setEditForm] = useState({
    name: '',
    cpf: '',
    group: '',
    quota: '',
    consortiumType: '',
    analystName: '',
    analystEmail: '',
    analystContemplation: ''
  });

  const categories = [
    DocumentType.ID,
    DocumentType.RESIDENCE,
    DocumentType.INCOME,
    DocumentType.CONTRACT
  ];

  const consortiumOptions = ['Imobiliário', 'Automotivo', 'Pesados', 'Serviços', 'Motos', 'Consórcio de Ouro', 'Outros Bens'];

  useEffect(() => {
    setEditForm({
      name: client.name,
      cpf: client.cpf,
      group: client.group,
      quota: client.quota,
      consortiumType: client.consortiumType,
      analystName: client.analystName,
      analystEmail: client.analystEmail || `${client.analystName.toLowerCase().replace(/\s+/g, '.')}@consorcioancora.com.br`,
      analystContemplation: client.analystContemplation
    });
  }, [client, isEditing]);

  const handleSaveInfo = () => {
    onUpdateClientInfo(editForm);
    setIsEditing(false);
  };

  const handleDeleteConfirm = () => {
    if (window.confirm(`Tem certeza que deseja excluir permanentemente o cadastro de ${client.name}? Esta ação não pode ser desfeita.`)) {
      onDeleteClient();
    }
  };

  const handleFinalizeProcess = async () => {
    // Permitir envio mesmo incompleto, mas com confirmação
    if (client.progress < 100) {
      const confirmIncomplete = window.confirm(
        `Atenção: A documentação está apenas ${client.progress}% completa. Deseja enviar o e-mail com os documentos atuais assim mesmo?`
      );
      if (!confirmIncomplete) return;
    }

    setIsFinalizing(true);

    try {
      const zip = new JSZip();
      const safeName = client.name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, '_');
      const folderName = `Documentos_${safeName}`;
      const folder = zip.folder(folderName);

      if (folder) {
        client.documents.forEach((doc) => {
          if (doc.fileData) {
            const base64Content = doc.fileData.split(',')[1];
            folder.file(`${doc.type.replace(/[^a-zA-Z0-9]/g, '_')}_${doc.fileName}`, base64Content, { base64: true });
          }
        });
      }

      const content = await zip.generateAsync({ type: 'blob' });
      const downloadLink = document.createElement('a');
      downloadLink.href = URL.createObjectURL(content);
      downloadLink.download = `${folderName}.zip`;
      document.body.appendChild(downloadLink);
      downloadLink.click();
      document.body.removeChild(downloadLink);

      const statusText = client.progress === 100 ? "COMPLETA" : `PARCIAL (${client.progress}%)`;
      const subject = encodeURIComponent(`[TRIAGEM ANCORADA] Documentação ${statusText} - ${client.name} (G: ${client.group} / C: ${client.quota})`);

      const missingDocs = categories
        .filter(cat => client.requiredDocumentTypes.includes(cat) && !client.documents.some(d => d.type === cat))
        .map(cat => `- ${cat}`)
        .join('\r\n');

      const body = encodeURIComponent(
        `Prezado(a) ${client.analystName},\r\n\r\n` +
        `A documentação do cliente ${client.name} foi processada no sistema TRIAGEM ANCORADA.\r\n\r\n` +
        `STATUS ATUAL: ${statusText}\r\n\r\n` +
        (client.progress < 100 ? `DOCUMENTOS PENDENTES:\r\n${missingDocs}\r\n\r\n` : '') +
        `>>> AÇÃO NECESSÁRIA: O arquivo ZIP com os documentos disponíveis foi baixado automaticamente. FAVOR ANEXAR O ARQUIVO '${folderName}.zip' A ESTE E-MAIL ANTES DE ENVIAR.\r\n\r\n` +
        `DADOS DO CLIENTE:\r\n` +
        `- Nome: ${client.name}\r\n` +
        `- Documento: ${client.cpf}\r\n` +
        `- Grupo/Cota: ${client.group} / ${client.quota}\r\n` +
        `- Segmento: ${client.consortiumType}\r\n\r\n` +
        `Atenciosamente,\r\n` +
        `Plataforma Triagem Ancorada`
      );

      const mailtoUrl = `mailto:${client.analystEmail}?subject=${subject}&body=${body}`;

      setTimeout(() => {
        setIsFinalizing(false);
        window.location.href = mailtoUrl;
        alert(`Processo Finalizado!\n\n1. O arquivo ZIP foi baixado.\n2. O Outlook será aberto.\n\nIMPORTANTE: Anexe o ZIP baixado manualmente ao e-mail.`);
      }, 1000);

    } catch (error) {
      console.error("Erro ao gerar pacote de documentos:", error);
      alert("Erro ao preparar os documentos para envio. Tente novamente.");
      setIsFinalizing(false);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, category: DocumentType) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(category);

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      const base64Data = (reader.result as string).split(',')[1];
      const result = await classifyDocument(base64Data);

      const newDoc: ClientDocument = {
        id: Math.random().toString(36).substr(2, 9),
        type: category,
        status: DocumentStatus.UPLOADED,
        fileName: file.name,
        fileData: reader.result as string,
        uploadDate: new Date().toISOString().split('T')[0],
        confidence: result.confidence
      };

      onAddDocument(newDoc);

      if (result.type !== category && result.type !== DocumentType.UNKNOWN) {
        alert(`Aviso de IA: O documento parece ser um "${result.type}", mas você está salvando em "${category}". Verifique se está correto.`);
      }

      setIsProcessing(null);
    };
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn pb-24">
      <div className="bg-white rounded-3xl shadow-sm border border-gray-200 p-8 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative">
        <div className="flex items-center gap-6 w-full">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-500 to-gray-600 rounded-3xl flex-shrink-0 flex items-center justify-center text-white text-3xl shadow-xl border-4 border-white">
            <i className={`fa-solid ${client.clientType === 'PF' ? 'fa-user' : 'fa-building-shield'}`}></i>
          </div>

          <div className="flex-grow">
            {!isEditing ? (
              <>
                <div className="flex items-center flex-wrap gap-3">
                  <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest border ${
                    client.clientType === 'PF' ? 'bg-blue-50 text-blue-600 border-blue-100' : 'bg-gray-100 text-gray-500 border-gray-200'
                  }`}>
                    {client.clientType === 'PF' ? 'Pessoa Física' : 'Pessoa Jurídica'}
                  </span>
                  <h2 className="text-3xl font-black text-gray-800 tracking-tight">{client.name}</h2>
                  <span className="px-3 py-1 bg-blue-50 text-blue-600 text-xs font-black rounded-full uppercase border border-blue-100">
                    {client.consortiumType}
                  </span>
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-amber-50 text-amber-700 text-xs font-black rounded-full uppercase border border-amber-100">
                    <i className="fa-solid fa-star"></i>
                    Contemplação: {client.analystContemplation}
                  </div>
                  <button 
                    onClick={() => setIsEditing(true)}
                    className="ml-2 p-2 text-gray-300 hover:text-blue-600 hover:bg-gray-50 rounded-full transition-all"
                    title="Editar informações"
                  >
                    <i className="fa-solid fa-pen-to-square text-lg"></i>
                  </button>
                </div>

                <div className="flex flex-wrap gap-x-6 gap-y-2 mt-2 text-sm text-gray-500 font-medium">
                  <span className="flex items-center gap-2"><i className="fa-solid fa-id-card text-gray-400"></i> {client.clientType === 'PF' ? 'CPF' : 'CNPJ'}: {client.cpf}</span>
                  <span className="flex items-center gap-2"><i className="fa-solid fa-tags text-gray-400"></i> Grupo/Cota: <b className="text-gray-700">{client.group} / {client.quota}</b></span>
                  <span className="flex items-center gap-2"><i className="fa-solid fa-envelope text-gray-400"></i> Analista: <b className="text-gray-700">{client.analystEmail}</b></span>
                </div>
              </>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 w-full pr-12 animate-slideUp">
                <div className="col-span-1 md:col-span-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{client.clientType === 'PF' ? 'Nome Completo' : 'Razão Social'}</label>
                  <input type="text" className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold" value={editForm.name} onChange={(e) => setEditForm({...editForm, name: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{client.clientType === 'PF' ? 'CPF' : 'CNPJ'}</label>
                  <input type="text" className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold" value={editForm.cpf} onChange={(e) => setEditForm({...editForm, cpf: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Email do Analista</label>
                  <input type="email" className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold" value={editForm.analystEmail} onChange={(e) => setEditForm({...editForm, analystEmail: e.target.value})} />
                </div>
                <div className="flex items-end gap-2 col-span-full justify-between mt-6 pt-6 border-t border-gray-100">
                  <button 
                    onClick={handleDeleteConfirm}
                    className="bg-red-50 text-red-600 px-6 py-2.5 rounded-xl text-sm font-black hover:bg-red-100 transition-all flex items-center gap-2"
                  >
                    <i className="fa-solid fa-trash-can"></i>
                    EXCLUIR CADASTRO
                  </button>
                  <div className="flex items-center gap-3">
                    <button onClick={() => setIsEditing(false)} className="bg-gray-100 text-gray-500 px-6 py-2.5 rounded-xl text-sm font-bold hover:bg-gray-200 transition-all">Cancelar</button>
                    <button onClick={handleSaveInfo} className="bg-blue-600 text-white px-8 py-2.5 rounded-xl text-sm font-black shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all">SALVAR DADOS</button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {!isEditing && (
          <div className="w-full md:w-auto flex flex-col items-end gap-2 bg-gray-50 p-6 rounded-2xl border border-gray-100">
