  }
];

export type ViewType = 'dashboard' | 'reports' | 'segments' | 'analysts' | 'management';

const App: React.FC = () => {
  // Inicializa o estado a partir do localStorage ou mock data
  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('ancora_clients');
    return saved ? JSON.parse(saved) : MOCK_CLIENTS;
  });

  const [analysts, setAnalysts] = useState<Analyst[]>(() => {
    const saved = localStorage.getItem('ancora_analysts');
    return saved ? JSON.parse(saved) : MOCK_ANALYSTS;
  });

  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Efeito para salvar clientes no localStorage sempre que houver mudança
  useEffect(() => {
    localStorage.setItem('ancora_clients', JSON.stringify(clients));
    setLastSaved(new Date());
  }, [clients]);

  // Efeito para salvar analistas no localStorage sempre que houver mudança
  useEffect(() => {
    localStorage.setItem('ancora_analysts', JSON.stringify(analysts));
    setLastSaved(new Date());
  }, [analysts]);

  const selectedClient = clients.find(c => c.id === selectedClientId);

  const calculateProgress = (docs: ClientDocument[], requiredTypes: DocumentType[]) => {
    if (requiredTypes.length === 0) return 100;
    const completedTypes = requiredTypes.filter(type => 
      docs.some(doc => doc.type === type && doc.status === DocumentStatus.UPLOADED)
    );
    return Math.round((completedTypes.length / requiredTypes.length) * 100);
  };

  const handleAddClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    setSelectedClientId(newClient.id);
    setIsAddModalOpen(false);
  };

  const handleAddAnalyst = (analyst: Analyst) => {
    setAnalysts(prev => [...prev, analyst]);
  };

  const handleUpdateAnalyst = (id: string, updates: Partial<Analyst>) => {
    const oldAnalyst = analysts.find(a => a.id === id);
    setAnalysts(prev => prev.map(a => a.id === id ? { ...a, ...updates } : a));

    if (updates.name && oldAnalyst) {
      setClients(prev => prev.map(c => ({
        ...c,
        analystName: c.analystName === oldAnalyst.name ? updates.name! : c.analystName,
        analystContemplation: c.analystContemplation === oldAnalyst.name ? updates.name! : c.analystContemplation
      })));
    }
  };

  const handleRemoveAnalyst = (id: string) => {
    if (window.confirm("Deseja realmente remover este analista? Isso não removerá os clientes, mas eles ficarão vinculados a um nome inexistente na lista de equipe.")) {
      setAnalysts(prev => prev.filter(a => a.id !== id));
    }
  };

  const handleAddDocument = (clientId: string, newDoc: ClientDocument) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = [...client.documents, newDoc];
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs, client.requiredDocumentTypes) 
      };
    }));
  };

  const handleRemoveDocument = (clientId: string, docId: string) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedDocs = client.documents.filter(d => d.id !== docId);
      return { 
        ...client, 
        documents: updatedDocs, 
        progress: calculateProgress(updatedDocs, client.requiredDocumentTypes) 
      };
    }));
  };

  const handleUpdateClientInfo = (clientId: string, updates: Partial<Client>) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const updatedClient = { ...client, ...updates };
      if (updates.requiredDocumentTypes || updates.documents) {
        updatedClient.progress = calculateProgress(updatedClient.documents, updatedClient.requiredDocumentTypes || client.requiredDocumentTypes);
      }
      return updatedClient;
    }));
  };

  const handleToggleRequirement = (clientId: string, docType: DocumentType) => {
    setClients(prev => prev.map(client => {
      if (client.id !== clientId) return client;
      const isCurrentlyRequired = client.requiredDocumentTypes.includes(docType);
      const newRequired = isCurrentlyRequired 
        ? client.requiredDocumentTypes.filter(t => t !== docType)
        : [...client.requiredDocumentTypes, docType];

      return {
        ...client,
        requiredDocumentTypes: newRequired,
        progress: calculateProgress(client.documents, newRequired)
      };
    }));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(client => client.id !== clientId));
    setSelectedClientId(null);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.cpf.includes(searchTerm) ||
    c.group.includes(searchTerm) ||
    c.quota.includes(searchTerm)
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <Header activeView={activeView} onViewChange={setActiveView} />

      <main className="flex-grow container mx-auto px-4 py-8 relative">
        {/* Indicador de Salvamento Automático */}
        <div className="absolute top-0 right-4 flex items-center gap-2 text-[10px] font-black text-emerald-500 uppercase tracking-widest pointer-events-none opacity-50">
