              >
                <i className="fa-solid fa-envelope-open-text text-2xl group-hover:rotate-12 transition-transform"></i>
              </button>
            )}
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 gap-6">
        {categories.map((category) => {
          const categoryDocs = client.documents.filter(d => d.type === category);
          const isComplete = categoryDocs.length > 0;
          const isRequired = client.requiredDocumentTypes.includes(category);

          return (
            <div key={category} className={`bg-white rounded-3xl border-2 p-8 transition-all duration-300 shadow-sm ${!isRequired ? 'border-gray-50 opacity-80' : isComplete ? 'border-emerald-100' : 'border-gray-100 hover:border-gray-200'}`}>
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-8">
                <div className="flex items-center gap-5">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-lg transition-transform hover:scale-105 ${!isRequired ? 'bg-gray-200 text-gray-400' : isComplete ? 'bg-emerald-500 text-white' : 'bg-gray-100 text-gray-400'}`}>
                    <i className={`fa-solid ${
                      category === DocumentType.ID ? 'fa-address-card' :
                      category === DocumentType.RESIDENCE ? 'fa-house' :
                      category === DocumentType.INCOME ? 'fa-receipt' : 
                      category === DocumentType.CONTRACT ? 'fa-file-signature' : 'fa-envelope-open-text'
                    }`}></i>
                  </div>
                  <div>
                    <div className="flex items-center gap-3">
                      <h3 className="text-xl font-black text-gray-800 tracking-tight">{category}</h3>
                      {!isRequired && (
                        <span className="px-2 py-0.5 bg-gray-100 text-gray-500 text-[10px] font-black rounded-lg uppercase tracking-widest border border-gray-200">OPCIONAL</span>
                      )}
                    </div>
                    <p className="text-sm text-gray-400 font-bold uppercase tracking-wider">
                      {isComplete ? `${categoryDocs.length} ARQUIVO(S) ENVIADO(S)` : isRequired ? 'PENDENTE DE ENVIO' : 'REQUISITO DESATIVADO'}
                    </p>
                  </div>
                </div>

                <div className="flex items-center gap-4">
                  <button 
                    onClick={() => onToggleRequirement(category)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border ${
                      isRequired 
                        ? 'bg-blue-50 text-blue-600 border-blue-200 hover:bg-blue-100' 
                        : 'bg-gray-50 text-gray-400 border-gray-200 hover:bg-gray-100'
                    }`}
                  >
                    <i className={`fa-solid ${isRequired ? 'fa-toggle-on' : 'fa-toggle-off'} text-lg`}></i>
                    {isRequired ? 'Obrigatório' : 'Caso Especial'}
                  </button>

                  <label className="flex items-center justify-center gap-3 bg-blue-600 text-white hover:bg-blue-700 px-6 py-3.5 rounded-2xl text-sm font-black cursor-pointer transition-all shadow-lg shadow-blue-100 active:scale-95 group">
                    {isProcessing === category ? (
                      <i className="fa-solid fa-circle-notch animate-spin"></i>
                    ) : (
                      <i className="fa-solid fa-arrow-up-from-bracket group-hover:-translate-y-1 transition-transform"></i>
                    )}
                    <span>{isComplete ? 'Substituir' : 'Enviar'}</span>
                    <input type="file" className="hidden" accept="image/*,application/pdf" onChange={(e) => handleFileUpload(e, category)} disabled={isProcessing !== null} />
                  </label>
                </div>
              </div>

              {categoryDocs.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {categoryDocs.map((doc) => (
                    <div key={doc.id} className="group bg-gray-50 border border-gray-100 rounded-2xl p-4 flex flex-col gap-3 hover:border-blue-300 hover:bg-white transition-all shadow-sm">
                      <div className="flex items-start justify-between">
                        <div className="flex items-center gap-3 overflow-hidden">
                          <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-red-500 border border-gray-100">
                             <i className="fa-solid fa-file-pdf"></i>
                          </div>
                          <div className="overflow-hidden">
                            <p className="text-sm font-black text-gray-700 truncate">{doc.fileName}</p>
                            <p className="text-[10px] text-gray-400 font-bold tracking-widest">{doc.uploadDate}</p>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button onClick={() => setViewingDoc(doc)} className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"><i className="fa-solid fa-eye"></i></button>
                          <button onClick={() => onRemoveDocument(doc.id)} className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"><i className="fa-solid fa-trash-can"></i></button>
                        </div>
                      </div>
                      {doc.confidence && (
                        <div className="flex items-center gap-2 text-[10px] text-blue-600 font-black bg-blue-50/70 py-1.5 px-3 rounded-xl border border-blue-100">
                          <i className="fa-solid fa-brain"></i>
                          <span>IA VALIDOU COM {(doc.confidence * 100).toFixed(0)}% DE PRECISÃO</span>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <div className="border-2 border-dashed border-gray-100 rounded-3xl py-12 text-center bg-gray-50/50">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-gray-200 mx-auto mb-4 shadow-sm border border-gray-50">
                    <i className={`fa-solid ${isRequired ? 'fa-file-shield' : 'fa-circle-info'} text-3xl`}></i>
                  </div>
                  <p className="text-sm text-gray-400 font-bold uppercase tracking-widest">
                    {isRequired ? 'Documento Obrigatório' : 'Documento Opcional'}
                  </p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* BARRA DE AÇÕES INFERIOR - REDIMENSIONADA */}
      <div className="fixed bottom-6 right-6 left-6 lg:left-1/3 xl:left-1/4 z-40">
        <div className="bg-gray-900 rounded-[24px] text-white p-4 flex flex-col sm:flex-row items-center justify-between gap-4 shadow-2xl border border-gray-800 max-w-4xl mx-auto overflow-hidden animate-slideUp">
          <div className="flex items-center gap-4">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg ${client.progress === 100 ? 'bg-emerald-500 shadow-emerald-500/20 shadow-lg' : 'bg-blue-600 text-white'}`}>
              <i className={`fa-solid ${client.progress === 100 ? 'fa-check-double' : 'fa-hourglass-half'}`}></i>
            </div>
            <div>
              <p className="font-black text-sm tracking-tight leading-tight uppercase">{client.progress === 100 ? 'Status: Documentação Completa' : 'Status: Pendente'}</p>
              <p className="text-[10px] text-gray-400 font-bold tracking-widest uppercase">{client.progress === 100 ? 'Pronto para envio final' : 'Envio parcial disponível'}</p>
            </div>
          </div>

          <button 
            disabled={isFinalizing} 
            onClick={handleFinalizeProcess}
            className={`px-6 py-2.5 rounded-xl font-black text-xs tracking-widest uppercase transition-all shadow-xl flex items-center gap-2.5 relative overflow-hidden group ${
              isFinalizing 
                ? 'bg-gray-800 text-gray-600 cursor-not-allowed'
                : client.progress === 100
                ? 'bg-gradient-to-r from-blue-600 to-gray-600 hover:from-blue-500 hover:to-gray-500 active:scale-95' 
                : 'bg-gradient-to-r from-blue-700 to-blue-900 hover:brightness-110 active:scale-95'
            }`}
          >
            {isFinalizing ? (
              <>
                <i className="fa-solid fa-circle-notch animate-spin"></i>
                <span>Processando...</span>
              </>
            ) : (
              <>
                <i className="fa-solid fa-paper-plane group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform"></i>
                <span>{client.progress === 100 ? 'Finalizar e Enviar' : 'Enviar Parcial'}</span>
              </>
            )}
            {!isFinalizing && (
              <span className="absolute inset-0 bg-white/10 animate-pulse pointer-events-none"></span>
            )}
          </button>
        </div>
      </div>

      {viewingDoc && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-gray-900/90 backdrop-blur-md animate-fadeIn">
          <div className="bg-white rounded-[40px] w-full max-w-5xl max-h-[90vh] flex flex-col shadow-2xl overflow-hidden animate-slideUp">
            <div className="p-8 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
              <div className="flex items-center gap-5">
                <div className="w-14 h-14 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-lg">
                  <i className="fa-solid fa-file-contract text-2xl"></i>
                </div>
                <div>
                  <h3 className="text-xl font-black text-gray-800 tracking-tight">{viewingDoc.type}</h3>
                  <p className="text-xs text-gray-400 font-bold tracking-widest uppercase">{viewingDoc.fileName}</p>
                </div>
              </div>
              <button onClick={() => setViewingDoc(null)} className="w-12 h-12 flex items-center justify-center text-gray-300 hover:text-gray-600 transition-colors rounded-full hover:bg-white shadow-sm border border-gray-100">
                <i className="fa-solid fa-xmark text-2xl"></i>
              </button>
            </div>
            <div className="flex-grow bg-gray-200 p-12 flex items-center justify-center overflow-auto custom-scrollbar">
              {viewingDoc.fileData ? (
                <div className="relative group">
                   <img src={viewingDoc.fileData} alt="Documento" className="max-w-full rounded-2xl shadow-2xl border-4 border-white" />
                   <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity rounded-2xl"></div>
                </div>
              ) : (
                <div className="text-center text-gray-400">
                  <i className="fa-solid fa-eye-slash text-6xl mb-6 opacity-20"></i>
                  <p className="font-bold">Prévia indisponível para este arquivo.</p>
                </div>
              )}
            </div>
            <div className="p-8 border-t border-gray-100 flex justify-end gap-4 bg-white">
               <button onClick={() => setViewingDoc(null)} className="px-8 py-3 bg-gray-100 text-gray-600 font-black rounded-2xl text-xs tracking-widest uppercase hover:bg-gray-200 transition-all">Fechar</button>
               <button className="px-10 py-3 bg-blue-600 text-white font-black rounded-2xl text-xs tracking-widest uppercase shadow-lg shadow-blue-100 flex items-center gap-3 hover:bg-blue-700 transition-all active:scale-95">
                 <i className="fa-solid fa-download"></i> Baixar Original
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ClientDetails;

import React, { useState } from 'react';
import { Client, DocumentType } from '../types';

interface DocumentManagementProps {
  clients: Client[];
}

type FilterType = 'pendentes' | 'concluidos';

const DocumentManagement: React.FC<DocumentManagementProps> = ({ clients }) => {
  const [activeTab, setActiveTab] = useState<FilterType>('pendentes');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');

  const pendentes = clients.filter(c => c.progress < 100);
  const concluidos = clients.filter(c => c.progress === 100);

  const displayedClients = (activeTab === 'pendentes' ? pendentes : concluidos).filter(c =>
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.cpf.includes(searchTerm) ||
    c.group.includes(searchTerm) ||
    c.quota.includes(searchTerm)
  );

  const categories = [
    DocumentType.ID,
    DocumentType.RESIDENCE,
    DocumentType.INCOME,
    DocumentType.CONTRACT,
    DocumentType.REQUEST_EMAIL
  ];

  const handleSelectAll = () => {
    if (selectedIds.size === displayedClients.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(displayedClients.map(c => c.id)));
    }
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const getMissingDocs = (client: Client) => {
    return categories.filter(cat => 
      client.requiredDocumentTypes.includes(cat) && 
      !client.documents.some(d => d.type === cat)
    );
  };

  const triggerEmail = (client: Client) => {
    if (activeTab === 'pendentes') {
      const missing = getMissingDocs(client);
      const docsList = missing.map(d => `- ${d}`).join('\r\n');
      const subject = encodeURIComponent(`[TRIAGEM ANCORADA] Pendência de Documentos - ${client.name}`);
      const body = encodeURIComponent(
        `Olá, ${client.name}.\r\n\r\n` +
        `Identificamos que ainda faltam documentos obrigatórios para o seu processo (G: ${client.group} / C: ${client.quota}).\r\n\r\n` +
        `DOCUMENTOS PENDENTES:\r\n${docsList}\r\n\r\n` +
        `Por favor, envie-os o quanto antes.\r\n\r\n` +
        `Atenciosamente,\r\nTriagem Ancorada`
      );
      window.location.href = `mailto:${client.email}?subject=${subject}&body=${body}`;
    } else {
      const subject = encodeURIComponent(`[TRIAGEM ANCORADA] Documentação Concluída - ${client.name}`);
      const body = encodeURIComponent(
        `Prezado(a) ${client.analystName},\r\n\r\n` +
        `A documentação do cliente ${client.name} está completa no sistema Triagem Ancorada.\r\n\r\n` +
        `DADOS: G: ${client.group} / C: ${client.quota}\r\n` +
        `STATUS: 100% CONCLUÍDO\r\n\r\n` +
        `Favor prosseguir com a análise.\r\n\r\n` +
        `Atenciosamente,\r\nPlataforma de Triagem`
      );
      window.location.href = `mailto:${client.analystEmail}?subject=${subject}&body=${body}`;
    }
  };

  const handleMassAction = () => {
    const selectedClients = clients.filter(c => selectedIds.has(c.id));
    if (selectedClients.length === 0) return;

    if (confirm(`Deseja iniciar o disparo de e-mails para ${selectedClients.length} clientes selecionados? (Serão abertas várias janelas de e-mail sequencialmente)`)) {
      selectedClients.forEach((c, index) => {
        setTimeout(() => triggerEmail(c), index * 800);
      });
    }
  };

  return (
    <div className="animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-end justify-between mb-10 gap-6">
        <div>
          <h2 className="text-3xl font-black text-gray-800 tracking-tight uppercase">Gestão de Envios</h2>
          <p className="text-gray-500 font-medium">Ações centralizadas para cobranças e notificações de analistas.</p>
        </div>

        <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-gray-200">
          <button 
            onClick={() => { setActiveTab('pendentes'); setSelectedIds(new Set()); }}
            className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
              activeTab === 'pendentes' ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            <i className="fa-solid fa-hourglass-half"></i>
            Pendentes ({pendentes.length})
          </button>
          <button 
            onClick={() => { setActiveTab('concluidos'); setSelectedIds(new Set()); }}
            className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
              activeTab === 'concluidos' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-100' : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            <i className="fa-solid fa-circle-check"></i>
            Concluídos ({concluidos.length})
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-gray-100 overflow-hidden mb-12">
        <div className="p-6 border-b border-gray-50 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="relative w-full md:w-96">
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" 
              placeholder="Pesquisar por nome, cota ou CPF..."
              className="w-full pl-11 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex items-center gap-3">
             {selectedIds.size > 0 && (
               <button 
                onClick={handleMassAction}
                className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl transition-all active:scale-95 ${
                  activeTab === 'pendentes' ? 'bg-amber-500 text-white shadow-amber-100' : 'bg-blue-600 text-white shadow-blue-100'
                }`}
               >
                 <i className="fa-solid fa-paper-plane"></i>
                 Disparar Selecionados ({selectedIds.size})
               </button>
             )}
          </div>
        </div>

        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50/50 text-gray-400">
                <th className="px-8 py-4 w-12">
                  <input 
                    type="checkbox" 
                    className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
                    checked={selectedIds.size === displayedClients.length && displayedClients.length > 0}
                    onChange={handleSelectAll}
                  />
                </th>
                <th className="px-4 py-4 text-[10px] font-black uppercase tracking-widest">Cliente</th>
                <th className="px-4 py-4 text-[10px] font-black uppercase tracking-widest">Grupo/Cota</th>
                <th className="px-4 py-4 text-[10px] font-black uppercase tracking-widest">
                  {activeTab === 'pendentes' ? 'Pendências' : 'Finalizado em'}
                </th>
                <th className="px-4 py-4 text-[10px] font-black uppercase tracking-widest text-right pr-8">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {displayedClients.length > 0 ? displayedClients.map(client => (
                <tr key={client.id} className={`hover:bg-gray-50/80 transition-colors group ${selectedIds.has(client.id) ? 'bg-blue-50/30' : ''}`}>
                  <td className="px-8 py-5">
                    <input 
                      type="checkbox" 
                      className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
                      checked={selectedIds.has(client.id)}
                      onChange={() => toggleSelect(client.id)}
                    />
                  </td>
                  <td className="px-4 py-5">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-sm shadow-sm ${
                        client.clientType === 'PF' ? 'bg-blue-50 text-blue-600' : 'bg-gray-100 text-gray-500'
                      }`}>
                        {client.name.charAt(0)}
                      </div>
                      <div>
                        <p className="text-sm font-black text-gray-800 group-hover:text-blue-600 transition-colors">{client.name}</p>
                        <p className="text-[10px] text-gray-400 font-bold uppercase">{client.email}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-5 font-bold text-gray-500 text-sm">
                    {client.group} / {client.quota}
                  </td>
                  <td className="px-4 py-5">
                    {activeTab === 'pendentes' ? (
                      <div className="flex flex-wrap gap-1.5 max-w-xs">
                        {getMissingDocs(client).map(doc => (
                          <span key={doc} className="px-2 py-0.5 bg-red-50 text-red-600 text-[8px] font-black uppercase rounded border border-red-100">
                            {doc.split(' ')[0]}
                          </span>
                        ))}
                      </div>
                    ) : (
                      <span className="text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100">
                        Pronto para análise
                      </span>
                    )}
                  </td>
                  <td className="px-4 py-5 text-right pr-8">
                    <button 
                      onClick={() => triggerEmail(client)}
                      className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95 shadow-sm border ${
                        activeTab === 'pendentes' 
                          ? 'bg-amber-50 text-amber-600 border-amber-100 hover:bg-amber-100' 
                          : 'bg-blue-50 text-blue-600 border-blue-100 hover:bg-blue-100'
                      }`}
                    >
                      <i className={`fa-solid ${activeTab === 'pendentes' ? 'fa-envelope-open-text' : 'fa-paper-plane'} mr-2`}></i>
                      {activeTab === 'pendentes' ? 'Cobrar' : 'Notificar'}
                    </button>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={5} className="py-24 text-center">
                    <div className="flex flex-col items-center">
                      <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center text-gray-200 mb-4">
                        <i className="fa-solid fa-folder-open text-3xl"></i>
                      </div>
                      <p className="text-gray-400 font-black uppercase text-xs tracking-widest">Nenhum registro encontrado</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
        <div className="bg-gradient-to-br from-gray-900 to-blue-900 rounded-[32px] p-8 text-white shadow-xl relative overflow-hidden group">
          <div className="absolute -right-10 -bottom-10 opacity-10 group-hover:scale-110 transition-transform duration-700">
            <i className="fa-solid fa-envelope-circle-check text-[180px]"></i>
          </div>
          <div className="relative z-10">
            <h4 className="text-lg font-black tracking-tight mb-2 uppercase">Fluxo de Cobrança Automática</h4>
            <p className="text-blue-100/70 text-sm font-medium mb-6 max-w-sm">Use as ações individuais ou em massa para manter os clientes engajados e sua esteira de documentação em dia.</p>
            <div className="flex items-center gap-4">
              <div className="px-4 py-2 bg-white/10 rounded-xl border border-white/10">
                <p className="text-[10px] font-black text-blue-300 uppercase tracking-widest mb-1">Média de Pendentes</p>
                <p className="text-2xl font-black">{clients.length > 0 ? Math.round((pendentes.length / clients.length) * 100) : 0}%</p>
              </div>
              <div className="px-4 py-2 bg-white/10 rounded-xl border border-white/10">
                <p className="text-[10px] font-black text-blue-300 uppercase tracking-widest mb-1">Cotas no Alvo</p>
                <p className="text-2xl font-black">{concluidos.length}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-[32px] p-8 shadow-sm border border-gray-100 flex items-center gap-8">
           <div className="w-24 h-24 rounded-3xl bg-emerald-50 text-emerald-600 flex items-center justify-center text-4xl shadow-lg border-2 border-white">
             <i className="fa-solid fa-check-double"></i>
           </div>
           <div>
              <h4 className="text-xl font-black text-gray-800 tracking-tight uppercase">Eficiência de Triagem</h4>
              <p className="text-gray-400 text-sm font-medium mb-4">A Triagem Ancorada valida documentos em segundos, reduzindo o tempo de espera do cliente final em até 40%.</p>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Sistema Operacional Online</span>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default DocumentManagement;

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const classifyDocument = async (base64Image: string): Promise<{ type: DocumentType, confidence: number }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            {
              inlineData: {
                mimeType: "image/jpeg",
                data: base64Image
              }
            },
            {
              text: "Analise esta imagem de documento e identifique se é um RG/CNH, Comprovante de Residência, Comprovante de Renda, Contrato de Consórcio ou um E-mail de Solicitação (print de tela ou PDF). Retorne o resultado em JSON."
            }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classification: {
              type: Type.STRING,
              description: "O tipo do documento: 'ID', 'RESIDENCE', 'INCOME', 'CONTRACT', 'REQUEST_EMAIL' ou 'UNKNOWN'"
            },
            confidence: {
              type: Type.NUMBER,
              description: "Nível de confiança de 0 a 1"
            }
          },
          required: ["classification", "confidence"]
        }
      }
    });

    const result = JSON.parse(response.text || "{}");

    const typeMap: Record<string, DocumentType> = {
      'ID': DocumentType.ID,
      'RESIDENCE': DocumentType.RESIDENCE,
      'INCOME': DocumentType.INCOME,
      'CONTRACT': DocumentType.CONTRACT,
      'REQUEST_EMAIL': DocumentType.REQUEST_EMAIL,
      'UNKNOWN': DocumentType.UNKNOWN
    };

    return {
      type: typeMap[result.classification] || DocumentType.UNKNOWN,
      confidence: result.confidence || 0
    };
  } catch (error) {
    console.error("Erro ao classificar documento:", error);
    return { type: DocumentType.UNKNOWN, confidence: 0 };
  }
};
